#[async_trait]
pub trait FinamRealOrderEndpointTransport: Send {
    async fn place_order_endpoint(
        &mut self,
        gate: &EndpointGateApproved,
        spec: broker_finam::FinamPlaceOrderRequestSpec,
    ) -> Result<
        broker_finam::FinamOrderEndpointClassifiedResponse,
        broker_finam::FinamOrderExecutionError,
    >;

    async fn cancel_order_endpoint(
        &mut self,
        gate: &EndpointGateApproved,
        spec: broker_finam::FinamCancelOrderRequestSpec,
    ) -> Result<
        broker_finam::FinamOrderEndpointClassifiedResponse,
        broker_finam::FinamOrderExecutionError,
    >;
}

/// Dry/mock endpoint transport boundary for M3b-4.
///
/// Implementations receive already approved broker-neutral request specs and
/// may only return a classified endpoint result plus redacted diagnostic. Raw
/// HTTP bodies and accepted response DTOs must remain inside the classifier
/// layer and must not cross this trait boundary.
pub trait FinamMockClassifiedEndpointTransport {
    fn place_order_endpoint_classified(
        &mut self,
        spec: broker_finam::FinamPlaceOrderRequestSpec,
    ) -> broker_finam::FinamOrderEndpointClassifiedResponse;

    fn cancel_order_endpoint_classified(
        &mut self,
        spec: broker_finam::FinamCancelOrderRequestSpec,
    ) -> broker_finam::FinamOrderEndpointClassifiedResponse;
}

fn m3c_order_endpoint_gate_design_checklist() -> Vec<M3cOrderEndpointGateDesignChecklistItem> {
    use M3cOrderEndpointGateDesignItem as Item;
    use M3cOrderEndpointGateDesignStatus as Status;
    [
        (
            Item::SeparateRealOrderEndpointFlagDefaultFalse,
            Status::DesignRecorded,
        ),
        (
            Item::SeparateCommandConsumerFlagDefaultFalse,
            Status::ImplementedAndTested,
        ),
        (
            Item::EndpointGateApprovedUnconstructibleUntilReview,
            Status::Blocked,
        ),
        (Item::OperatorArmOneShotTtl, Status::ImplementedAndTested),
        (Item::AccountAllowlist, Status::DesignRecorded),
        (Item::InstrumentAllowlist, Status::DesignRecorded),
        (
            Item::OrderTypeTifQuantityNotionalPriceGuards,
            Status::ImplementedAndTested,
        ),
        (
            Item::SqliteDurableStoreMandatory,
            Status::ImplementedAndTested,
        ),
        (
            Item::UnknownActiveBrokerOrderStartupGuard,
            Status::DesignRecorded,
        ),
        (Item::RateLimitBackoffPolicy, Status::ImplementedAndTested),
        (
            Item::NoBlindRetryAfterSubmitOrCancelTimeout,
            Status::ImplementedAndTested,
        ),
        (
            Item::ManualInterventionStateAndRunbook,
            Status::ImplementedAndTested,
        ),
        (Item::RedactedAckExportPolicy, Status::ImplementedAndTested),
        (
            Item::ForbiddenSurfaceScanExtensionPlan,
            Status::DesignRecorded,
        ),
        (Item::ReleaseProfileEvidenceOrWaiver, Status::DesignRecorded),
        (Item::RouteTemplateRecheck, Status::DesignRecorded),
        (
            Item::PositiveGetOrderEvidenceOrWaiver,
            Status::DesignRecorded,
        ),
    ]
    .into_iter()
    .map(|(item, status)| M3cOrderEndpointGateDesignChecklistItem { item, status })
    .collect()
}

