#[derive(Debug, Clone)]
pub struct M3eCommandConsumerDryRun<S> {
    config: M3eCommandConsumerConfig,
    sink: S,
}

impl<S> M3eCommandConsumerDryRun<S>
where
    S: RedisStreamSink,
{
    pub fn new(config: M3eCommandConsumerConfig, sink: S) -> Self {
        Self { config, sink }
    }

    pub fn from_gateway_config(config: &GatewayConfig, sink: S) -> Self {
        Self::new(M3eCommandConsumerConfig::from_gateway_config(config), sink)
    }

    pub async fn process_entry(
        &self,
        entry: RuntimeBridgeStreamEntry,
        now: DateTime<Utc>,
    ) -> Result<M3eCommandConsumerReport, GatewayError> {
        match decode_m3e_command_entry(&entry, &self.config, now) {
            Ok(command_decision) => {
                let ack = command_decision.into_ack(now);
                let ack_status = ack.status;
                let ack_reason_code = ack.reason.as_ref().map(|reason| reason.code);
                self.sink
                    .publish_json(
                        &self.config.command_ack_stream,
                        &Envelope::new(
                            self.config.source.clone(),
                            MessageType::CommandAck,
                            redact_command_ack_for_redis(ack),
                        ),
                        self.config.command_ack_maxlen,
                    )
                    .await?;
                Ok(M3eCommandConsumerReport {
                    action: M3eCommandConsumerAction::AckPublished,
                    entry_id: entry.entry_id,
                    ack_status: Some(ack_status),
                    ack_reason_code,
                    dlq_reason: None,
                    xack_applied: true,
                    xack_after_ack_or_dlq_publish: true,
                    endpoint_transport_invoked: false,
                    external_order_endpoint_allowed: false,
                    raw_payload_exported: false,
                    raw_token_exported: false,
                    raw_body_exported: false,
                    raw_command_comment_exported: false,
                })
            }
            Err(dead_letter) => {
                let reason = dead_letter.reason.clone();
                let record = M3eCommandDlqRecord::new(&self.config, dead_letter);
                self.sink
                    .publish_json(
                        &self.config.command_dlq_stream,
                        &record,
                        self.config.command_dlq_maxlen,
                    )
                    .await?;
                Ok(M3eCommandConsumerReport {
                    action: M3eCommandConsumerAction::DlqPublished,
                    entry_id: entry.entry_id,
                    ack_status: None,
                    ack_reason_code: None,
                    dlq_reason: Some(reason),
                    xack_applied: true,
                    xack_after_ack_or_dlq_publish: true,
                    endpoint_transport_invoked: false,
                    external_order_endpoint_allowed: false,
                    raw_payload_exported: false,
                    raw_token_exported: false,
                    raw_body_exported: false,
                    raw_command_comment_exported: false,
                })
            }
        }
    }
}

#[derive(Debug, Clone)]
pub struct M3eCommandConsumerDurableDryRun<S, L> {
    config: M3eCommandConsumerConfig,
    sink: S,
    lifecycle_store: L,
}

impl<S, L> M3eCommandConsumerDurableDryRun<S, L>
where
    S: RedisStreamSink,
    L: M3eCommandLifecycleStore,
{
    pub fn new(config: M3eCommandConsumerConfig, sink: S, lifecycle_store: L) -> Self {
        Self {
            config,
            sink,
            lifecycle_store,
        }
    }

    pub fn from_gateway_config(config: &GatewayConfig, sink: S, lifecycle_store: L) -> Self {
        Self::new(
            M3eCommandConsumerConfig::from_gateway_config(config),
            sink,
            lifecycle_store,
        )
    }

    pub async fn process_entry(
        &self,
        entry: RuntimeBridgeStreamEntry,
        now: DateTime<Utc>,
    ) -> Result<M3eCommandConsumerDurableReport, GatewayError> {
        match decode_m3e_command_entry(&entry, &self.config, now) {
            Ok(command_decision) => {
                self.process_typed_command(entry, command_decision, now)
                    .await
            }
            Err(dead_letter) => self.publish_dlq(entry, dead_letter).await,
        }
    }

    async fn process_typed_command(
        &self,
        entry: RuntimeBridgeStreamEntry,
        command_decision: M3eCommandDecision,
        now: DateTime<Utc>,
    ) -> Result<M3eCommandConsumerDurableReport, GatewayError> {
        let request_id = command_decision.request_id();
        if let Some(existing) = self.lifecycle_store.load_by_request_id(request_id)? {
            return self.publish_duplicate_ack(entry, existing, now).await;
        }

        let mut record = M3eCommandLifecycleRecord::command_received(
            entry.entry_id.clone(),
            command_decision.command(),
            now,
        );
        let inserted = self.lifecycle_store.insert_received(record.clone())?;
        if !inserted {
            let existing = self.lifecycle_store.load_by_request_id(request_id)?.ok_or(
                GatewayError::InternalState {
                    message: "m3e command lifecycle duplicate disappeared",
                },
            )?;
            return self.publish_duplicate_ack(entry, existing, now).await;
        }

        let ack = command_decision.into_ack(now);
        let ack_status = ack.status;
        let ack_reason_code = ack.reason.as_ref().map(|reason| reason.code);
        self.publish_ack(ack).await?;
        record.mark_ack_published(ack_status, ack_reason_code, now, true);
        self.lifecycle_store.upsert(record.clone())?;

        Ok(M3eCommandConsumerDurableReport {
            action: if ack_status == CommandAckStatus::Expired {
                M3eCommandLifecycleAction::ExpiredAckPublished
            } else {
                M3eCommandLifecycleAction::CommandReceived
            },
            entry_id: entry.entry_id,
            request_id: Some(request_id),
            ack_status: Some(ack_status),
            ack_reason_code,
            dlq_reason: None,
            lifecycle_state: Some(record.state),
            command_received_persisted: true,
            request_id_idempotency_store_hit: false,
            duplicate_request: false,
            duplicate_request_no_second_endpoint_attempt: true,
            endpoint_attempt_count: record.endpoint_attempt_count,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: false,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_duplicate_ack(
        &self,
        entry: RuntimeBridgeStreamEntry,
        mut existing: M3eCommandLifecycleRecord,
        now: DateTime<Utc>,
    ) -> Result<M3eCommandConsumerDurableReport, GatewayError> {
        let ack = CommandAck {
            request_id: existing.request_id,
            client_order_id: None,
            broker_order_id: None,
            status: CommandAckStatus::Duplicate,
            reason: Some(CommandAckReason::new(
                CommandAckReasonCode::DuplicateCommand,
            )),
            received_ts: now,
        };
        self.publish_ack(ack).await?;
        existing.mark_duplicate_ack_published(now);
        self.lifecycle_store.upsert(existing.clone())?;

        Ok(M3eCommandConsumerDurableReport {
            action: if existing.ack_publish_count == 0 {
                M3eCommandLifecycleAction::RecoveredAckPublished
            } else {
                M3eCommandLifecycleAction::DuplicateAckPublished
            },
            entry_id: entry.entry_id,
            request_id: Some(existing.request_id),
            ack_status: Some(CommandAckStatus::Duplicate),
            ack_reason_code: Some(CommandAckReasonCode::DuplicateCommand),
            dlq_reason: None,
            lifecycle_state: Some(existing.state),
            command_received_persisted: true,
            request_id_idempotency_store_hit: true,
            duplicate_request: true,
            duplicate_request_no_second_endpoint_attempt: existing.endpoint_attempt_count == 0,
            endpoint_attempt_count: existing.endpoint_attempt_count,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: false,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_dlq(
        &self,
        entry: RuntimeBridgeStreamEntry,
        dead_letter: M3eCommandDeadLetter,
    ) -> Result<M3eCommandConsumerDurableReport, GatewayError> {
        let reason = dead_letter.reason.clone();
        let record = M3eCommandDlqRecord::new(&self.config, dead_letter);
        self.sink
            .publish_json(
                &self.config.command_dlq_stream,
                &record,
                self.config.command_dlq_maxlen,
            )
            .await?;
        Ok(M3eCommandConsumerDurableReport {
            action: M3eCommandLifecycleAction::DlqPublished,
            entry_id: entry.entry_id,
            request_id: None,
            ack_status: None,
            ack_reason_code: None,
            dlq_reason: Some(reason),
            lifecycle_state: None,
            command_received_persisted: false,
            request_id_idempotency_store_hit: false,
            duplicate_request: false,
            duplicate_request_no_second_endpoint_attempt: true,
            endpoint_attempt_count: 0,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: false,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_ack(&self, ack: CommandAck) -> Result<(), GatewayError> {
        self.sink
            .publish_json(
                &self.config.command_ack_stream,
                &Envelope::new(
                    self.config.source.clone(),
                    MessageType::CommandAck,
                    redact_command_ack_for_redis(ack),
                ),
                self.config.command_ack_maxlen,
            )
            .await
    }
}

#[derive(Debug, Clone)]
pub struct M3eCommandConsumerLocalMockEndpoint<S, L> {
    config: M3eCommandConsumerConfig,
    sink: S,
    lifecycle_store: L,
}

impl<S, L> M3eCommandConsumerLocalMockEndpoint<S, L>
where
    S: RedisStreamSink,
    L: M3eCommandLifecycleStore,
{
    pub fn new(config: M3eCommandConsumerConfig, sink: S, lifecycle_store: L) -> Self {
        Self {
            config,
            sink,
            lifecycle_store,
        }
    }

    pub async fn process_entry<OS, T>(
        &self,
        entry: RuntimeBridgeStreamEntry,
        order_store: &mut OS,
        transport: &mut T,
        preflight_policy: &OrderPreflightPolicy,
        now: DateTime<Utc>,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError>
    where
        OS: OrderPathStore,
        T: FinamMockClassifiedEndpointTransport,
    {
        let runtime = M3eLocalMockEndpointRuntime {
            order_store,
            transport,
            preflight_policy,
            now,
        };
        match decode_m3e_command_entry(&entry, &self.config, now) {
            Ok(command_decision) => {
                self.process_typed_command(entry, command_decision, runtime)
                    .await
            }
            Err(dead_letter) => self.publish_dlq(entry, dead_letter).await,
        }
    }

    async fn process_typed_command<OS, T>(
        &self,
        entry: RuntimeBridgeStreamEntry,
        command_decision: M3eCommandDecision,
        runtime: M3eLocalMockEndpointRuntime<'_, OS, T>,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError>
    where
        OS: OrderPathStore,
        T: FinamMockClassifiedEndpointTransport,
    {
        let now = runtime.now;
        let request_id = command_decision.request_id();
        if let Some(existing) = self.lifecycle_store.load_by_request_id(request_id)? {
            return self.publish_duplicate_ack(entry, existing, now).await;
        }

        let lifecycle_record = M3eCommandLifecycleRecord::command_received(
            entry.entry_id.clone(),
            command_decision.command(),
            now,
        );
        let inserted = self
            .lifecycle_store
            .insert_received(lifecycle_record.clone())?;
        if !inserted {
            let existing = self.lifecycle_store.load_by_request_id(request_id)?.ok_or(
                GatewayError::InternalState {
                    message: "m3e local mock lifecycle duplicate disappeared",
                },
            )?;
            return self.publish_duplicate_ack(entry, existing, now).await;
        }

        if matches!(command_decision, M3eCommandDecision::Expired(_)) {
            let ack = command_decision.into_ack(now);
            return self
                .publish_planned_ack_report(M3ePlannedAckReportInput {
                    entry,
                    lifecycle_record,
                    ack,
                    action: M3eCommandLifecycleAction::ExpiredAckPublished,
                    order_path_state: None,
                    endpoint_outcome: None,
                    preflight_local_reject_before_endpoint: false,
                    endpoint_attempt_count: 0,
                    now,
                })
                .await;
        }

        match command_decision.command() {
            BrokerCommand::PlaceOrder(order) => {
                self.process_place_order(entry, order.clone(), lifecycle_record, runtime)
                    .await
            }
            BrokerCommand::CancelOrder(cancel) => {
                self.process_cancel_order(entry, cancel.clone(), lifecycle_record, runtime)
                    .await
            }
        }
    }

    async fn process_place_order<OS, T>(
        &self,
        entry: RuntimeBridgeStreamEntry,
        order: broker_core::PlaceOrder,
        lifecycle_record: M3eCommandLifecycleRecord,
        runtime: M3eLocalMockEndpointRuntime<'_, OS, T>,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError>
    where
        OS: OrderPathStore,
        T: FinamMockClassifiedEndpointTransport,
    {
        let now = runtime.now;
        let approved = match runtime.preflight_policy.approve_place_order(&order, now) {
            Ok(approved) => approved,
            Err(_error) => {
                let ack = CommandAck {
                    request_id: order.request_id,
                    client_order_id: Some(order.client_order_id.clone()),
                    broker_order_id: None,
                    status: CommandAckStatus::Rejected,
                    reason: Some(CommandAckReason::new(
                        CommandAckReasonCode::LocalValidationRejected,
                    )),
                    received_ts: now,
                };
                return self
                    .publish_planned_ack_report(M3ePlannedAckReportInput {
                        entry,
                        lifecycle_record,
                        ack,
                        action: M3eCommandLifecycleAction::LocalRejectAckPublished,
                        order_path_state: None,
                        endpoint_outcome: None,
                        preflight_local_reject_before_endpoint: true,
                        endpoint_attempt_count: 0,
                        now,
                    })
                    .await;
            }
        };

        runtime
            .order_store
            .insert_intent(OrderPathRecord::from_place_order(&order, now, None))?;
        let endpoint_report = simulate_place_order_endpoint_classified_transport(
            runtime.order_store,
            runtime.transport,
            &approved,
            None,
            None,
            now,
            now,
        )?;
        let ack = endpoint_report.ack.clone();
        let endpoint_attempt_count = endpoint_report.submit_attempt_count;
        self.publish_planned_ack_report(M3ePlannedAckReportInput {
            entry,
            lifecycle_record,
            ack,
            action: M3eCommandLifecycleAction::LocalMockEndpointAckPublished,
            order_path_state: Some(endpoint_report.state),
            endpoint_outcome: Some(endpoint_report.outcome),
            preflight_local_reject_before_endpoint: false,
            endpoint_attempt_count,
            now,
        })
        .await
    }

    async fn process_cancel_order<OS, T>(
        &self,
        entry: RuntimeBridgeStreamEntry,
        cancel: broker_core::CancelOrder,
        lifecycle_record: M3eCommandLifecycleRecord,
        runtime: M3eLocalMockEndpointRuntime<'_, OS, T>,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError>
    where
        OS: OrderPathStore,
        T: FinamMockClassifiedEndpointTransport,
    {
        let now = runtime.now;
        let existing = runtime
            .order_store
            .load_by_broker_order_id(&cancel.order_id);
        let approved =
            match runtime
                .preflight_policy
                .approve_cancel_order(&cancel, now, existing.as_ref())
            {
                Ok(CancelPreflightApproval::Submit(approved)) => approved,
                Ok(CancelPreflightApproval::AlreadyTerminal) | Err(_) => {
                    let ack = CommandAck {
                        request_id: cancel.request_id,
                        client_order_id: cancel.client_order_id.clone(),
                        broker_order_id: Some(cancel.order_id.clone()),
                        status: CommandAckStatus::Rejected,
                        reason: Some(CommandAckReason::new(
                            CommandAckReasonCode::LocalValidationRejected,
                        )),
                        received_ts: now,
                    };
                    return self
                        .publish_planned_ack_report(M3ePlannedAckReportInput {
                            entry,
                            lifecycle_record,
                            ack,
                            action: M3eCommandLifecycleAction::LocalRejectAckPublished,
                            order_path_state: existing.map(|record| record.state),
                            endpoint_outcome: None,
                            preflight_local_reject_before_endpoint: true,
                            endpoint_attempt_count: 0,
                            now,
                        })
                        .await;
                }
            };

        let endpoint_report = simulate_cancel_order_endpoint_classified_transport(
            runtime.order_store,
            runtime.transport,
            &approved,
            None,
            now,
            now,
        )?;
        let ack = CommandAck {
            request_id: cancel.request_id,
            client_order_id: cancel.client_order_id.clone(),
            broker_order_id: Some(cancel.order_id.clone()),
            status: endpoint_report.ack.status,
            reason: endpoint_report.ack.reason.clone(),
            received_ts: endpoint_report.ack.received_ts,
        };
        let endpoint_attempt_count = endpoint_report.cancel_attempt_count;
        self.publish_planned_ack_report(M3ePlannedAckReportInput {
            entry,
            lifecycle_record,
            ack,
            action: M3eCommandLifecycleAction::LocalMockEndpointAckPublished,
            order_path_state: Some(endpoint_report.state),
            endpoint_outcome: Some(endpoint_report.outcome),
            preflight_local_reject_before_endpoint: false,
            endpoint_attempt_count,
            now,
        })
        .await
    }

    async fn publish_planned_ack_report(
        &self,
        input: M3ePlannedAckReportInput,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError> {
        let M3ePlannedAckReportInput {
            entry,
            mut lifecycle_record,
            ack,
            action,
            order_path_state,
            endpoint_outcome,
            preflight_local_reject_before_endpoint,
            endpoint_attempt_count,
            now,
        } = input;
        let ack_status = ack.status;
        let ack_reason_code = ack.reason.as_ref().map(|reason| reason.code);
        lifecycle_record.mark_ack_publish_planned(
            ack_status,
            ack_reason_code,
            now,
            endpoint_attempt_count,
        );
        self.lifecycle_store.upsert(lifecycle_record.clone())?;
        self.publish_ack(ack).await?;
        lifecycle_record.mark_ack_published(ack_status, ack_reason_code, now, true);
        self.lifecycle_store.upsert(lifecycle_record.clone())?;

        Ok(M3eLocalMockEndpointCommandReport {
            action,
            entry_id: entry.entry_id,
            request_id: Some(lifecycle_record.request_id),
            ack_status: Some(ack_status),
            ack_reason_code,
            dlq_reason: None,
            lifecycle_state: Some(lifecycle_record.state),
            order_path_state,
            endpoint_outcome,
            command_received_persisted: true,
            request_id_idempotency_store_hit: false,
            duplicate_request: false,
            duplicate_request_no_second_endpoint_attempt: true,
            preflight_local_reject_before_endpoint,
            begin_submit_or_request_cancel_persisted_before_endpoint: endpoint_attempt_count > 0,
            endpoint_attempt_count,
            endpoint_attempt_count_incremented_only_after_durable_boundary: true,
            local_mock_endpoint_only: true,
            non_loopback_endpoint_allowed: false,
            ack_publish_planned_before_ack: true,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: endpoint_attempt_count > 0,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_duplicate_ack(
        &self,
        entry: RuntimeBridgeStreamEntry,
        mut existing: M3eCommandLifecycleRecord,
        now: DateTime<Utc>,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError> {
        let action = if existing.state == M3eCommandLifecycleState::AckPublishPlanned {
            M3eCommandLifecycleAction::RecoveredAckPublished
        } else {
            M3eCommandLifecycleAction::DuplicateAckPublished
        };
        let prior_endpoint_attempt_count = existing.endpoint_attempt_count;
        let ack = CommandAck {
            request_id: existing.request_id,
            client_order_id: None,
            broker_order_id: None,
            status: CommandAckStatus::Duplicate,
            reason: Some(CommandAckReason::new(
                CommandAckReasonCode::DuplicateCommand,
            )),
            received_ts: now,
        };
        self.publish_ack(ack).await?;
        existing.mark_duplicate_ack_published(now);
        self.lifecycle_store.upsert(existing.clone())?;

        Ok(M3eLocalMockEndpointCommandReport {
            action,
            entry_id: entry.entry_id,
            request_id: Some(existing.request_id),
            ack_status: Some(CommandAckStatus::Duplicate),
            ack_reason_code: Some(CommandAckReasonCode::DuplicateCommand),
            dlq_reason: None,
            lifecycle_state: Some(existing.state),
            order_path_state: None,
            endpoint_outcome: None,
            command_received_persisted: true,
            request_id_idempotency_store_hit: true,
            duplicate_request: true,
            duplicate_request_no_second_endpoint_attempt: true,
            preflight_local_reject_before_endpoint: false,
            begin_submit_or_request_cancel_persisted_before_endpoint: prior_endpoint_attempt_count
                > 0,
            endpoint_attempt_count: prior_endpoint_attempt_count,
            endpoint_attempt_count_incremented_only_after_durable_boundary: true,
            local_mock_endpoint_only: true,
            non_loopback_endpoint_allowed: false,
            ack_publish_planned_before_ack: existing.state
                == M3eCommandLifecycleState::AckPublishPlanned,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: false,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_dlq(
        &self,
        entry: RuntimeBridgeStreamEntry,
        dead_letter: M3eCommandDeadLetter,
    ) -> Result<M3eLocalMockEndpointCommandReport, GatewayError> {
        let reason = dead_letter.reason.clone();
        let record = M3eCommandDlqRecord::new(&self.config, dead_letter);
        self.sink
            .publish_json(
                &self.config.command_dlq_stream,
                &record,
                self.config.command_dlq_maxlen,
            )
            .await?;
        Ok(M3eLocalMockEndpointCommandReport {
            action: M3eCommandLifecycleAction::DlqPublished,
            entry_id: entry.entry_id,
            request_id: None,
            ack_status: None,
            ack_reason_code: None,
            dlq_reason: Some(reason),
            lifecycle_state: None,
            order_path_state: None,
            endpoint_outcome: None,
            command_received_persisted: false,
            request_id_idempotency_store_hit: false,
            duplicate_request: false,
            duplicate_request_no_second_endpoint_attempt: true,
            preflight_local_reject_before_endpoint: false,
            begin_submit_or_request_cancel_persisted_before_endpoint: false,
            endpoint_attempt_count: 0,
            endpoint_attempt_count_incremented_only_after_durable_boundary: true,
            local_mock_endpoint_only: true,
            non_loopback_endpoint_allowed: false,
            ack_publish_planned_before_ack: false,
            ack_publish_before_xack: true,
            xack_applied: true,
            xack_after_ack_or_dlq_publish: true,
            endpoint_transport_invoked: false,
            external_order_endpoint_allowed: false,
            raw_payload_exported: false,
            raw_token_exported: false,
            raw_body_exported: false,
            raw_command_comment_exported: false,
        })
    }

    async fn publish_ack(&self, ack: CommandAck) -> Result<(), GatewayError> {
        self.sink
            .publish_json(
                &self.config.command_ack_stream,
                &Envelope::new(
                    self.config.source.clone(),
                    MessageType::CommandAck,
                    redact_command_ack_for_redis(ack),
                ),
                self.config.command_ack_maxlen,
            )
            .await
    }
}

#[derive(Debug, Clone, PartialEq)]
enum M3eCommandDecision {
    DryRunRejected(BrokerCommand),
    Expired(BrokerCommand),
}

impl M3eCommandDecision {
    fn command(&self) -> &BrokerCommand {
        match self {
            Self::DryRunRejected(command) | Self::Expired(command) => command,
        }
    }

    fn request_id(&self) -> StrategyRequestId {
        command_request_id(self.command())
    }

    fn into_ack(self, now: DateTime<Utc>) -> CommandAck {
        match self {
            Self::DryRunRejected(command) => CommandAck {
                request_id: command_request_id(&command),
                client_order_id: command_client_order_id(&command),
                broker_order_id: None,
                status: CommandAckStatus::Rejected,
                reason: Some(CommandAckReason::new(CommandAckReasonCode::DryRunOnly)),
                received_ts: now,
            },
            Self::Expired(command) => CommandAck {
                request_id: command_request_id(&command),
                client_order_id: command_client_order_id(&command),
                broker_order_id: None,
                status: CommandAckStatus::Expired,
                reason: Some(CommandAckReason::new(CommandAckReasonCode::ExpiredCommand)),
                received_ts: now,
            },
        }
    }
}

fn decode_m3e_command_entry(
    entry: &RuntimeBridgeStreamEntry,
    config: &M3eCommandConsumerConfig,
    now: DateTime<Utc>,
) -> Result<M3eCommandDecision, M3eCommandDeadLetter> {
    if entry.stream != config.command_stream {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::UnknownStream,
        ));
    }
    let value = serde_json::from_str::<serde_json::Value>(&entry.payload)
        .map_err(|_| m3e_command_dead_letter(entry, M3eCommandDlqReason::InvalidJson))?;
    let schema_version = value
        .get("schema_version")
        .and_then(serde_json::Value::as_u64);
    let Some(schema_version) = schema_version else {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::MissingSchemaVersion,
        ));
    };
    if schema_version != u64::from(SCHEMA_VERSION) {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::UnsupportedSchemaVersion {
                expected: SCHEMA_VERSION,
                actual: schema_version,
            },
        ));
    }
    let msg_type = value.get("msg_type");
    let Some(msg_type) = msg_type else {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::MissingMessageType,
        ));
    };
    let actual_msg_type = serde_json::from_value::<MessageType>(msg_type.clone()).ok();
    if actual_msg_type != Some(MessageType::Command) {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::MessageTypeMismatch {
                expected: MessageType::Command,
                actual: actual_msg_type,
            },
        ));
    }
    if value.get("payload").is_none() {
        return Err(m3e_command_dead_letter(
            entry,
            M3eCommandDlqReason::MissingPayload,
        ));
    }
    let envelope = serde_json::from_value::<Envelope<BrokerCommand>>(value)
        .map_err(|_| m3e_command_dead_letter(entry, M3eCommandDlqReason::TypedDecodeFailed))?;
    if command_expired(&envelope.payload, now) {
        Ok(M3eCommandDecision::Expired(envelope.payload))
    } else {
        Ok(M3eCommandDecision::DryRunRejected(envelope.payload))
    }
}

fn m3e_command_dead_letter(
    entry: &RuntimeBridgeStreamEntry,
    reason: M3eCommandDlqReason,
) -> M3eCommandDeadLetter {
    M3eCommandDeadLetter {
        stream: entry.stream.clone(),
        entry_id: entry.entry_id.clone(),
        reason,
        payload_len: entry.payload.len(),
        raw_payload_exported: false,
    }
}

fn command_expired(command: &BrokerCommand, now: DateTime<Utc>) -> bool {
    let (created_ts, ttl_ms) = match command {
        BrokerCommand::PlaceOrder(order) => (order.created_ts, order.ttl_ms),
        BrokerCommand::CancelOrder(order) => (order.created_ts, order.ttl_ms),
    };
    ttl_ms.is_some_and(|ttl_ms| created_ts + ChronoDuration::milliseconds(ttl_ms as i64) < now)
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum RuntimeBridgeConsumeOutcome {
    Accepted {
        kind: RuntimeBridgePayloadKind,
        entry_id: String,
    },
    DuplicateBar {
        entry_id: String,
        bar_key: String,
    },
    DeadLetter(RuntimeBridgeDeadLetter),
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct RuntimeBridgeConsumerMetrics {
    pub entries_seen: u64,
    pub accepted_count: u64,
    pub duplicate_bar_count: u64,
    pub dlq_count: u64,
    pub health_count: u64,
    pub readiness_count: u64,
    pub portfolio_snapshot_count: u64,
    pub order_snapshot_count: u64,
    pub market_data_count: u64,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum RuntimeBridgeDryReadinessPhase {
    WaitingForInputs,
    DryReady,
    Degraded,
    Blocked,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum RuntimeBridgeDryReadinessReason {
    HealthMissing,
    HealthNotReadOnly { status: GatewayHealthStatus },
    GatewayReadinessMissing,
    GatewayReadinessNotReconciliation { phase: ReadinessPhase },
    PortfolioSnapshotMissing,
    OrderSnapshotMissing,
    MarketDataMissing,
    UnknownOpenOrders,
    DeadLettersPresent { count: u64 },
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct RuntimeBridgeReadinessState {
    pub health_seen: bool,
    pub health_status: Option<GatewayHealthStatus>,
    pub gateway_readiness_seen: bool,
    pub gateway_readiness_phase: Option<ReadinessPhase>,
    pub portfolio_snapshot_seen: bool,
    pub order_snapshot_seen: bool,
    pub market_data_seen: bool,
    pub blocking_unknown_orders: bool,
    pub dead_letter_count: u64,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct RuntimeBridgeReadinessDecision {
    pub schema_version: u16,
    pub live_ready: bool,
    pub phase: RuntimeBridgeDryReadinessPhase,
    pub reasons: Vec<RuntimeBridgeDryReadinessReason>,
    pub state: RuntimeBridgeReadinessState,
}

#[derive(Debug, Clone)]
pub struct RuntimeBridgeReadinessSimulator {
    config: RedisStreamConfig,
    state: RuntimeBridgeReadinessState,
}

impl RuntimeBridgeReadinessSimulator {
    pub fn new(config: RedisStreamConfig) -> Self {
        Self {
            config,
            state: RuntimeBridgeReadinessState::default(),
        }
    }

    pub fn from_gateway_config(config: &GatewayConfig) -> Self {
        Self::new(config.redis.clone())
    }

    pub fn observe_entry(
        &mut self,
        entry: &RuntimeBridgeStreamEntry,
    ) -> Result<(), RuntimeBridgeDeadLetter> {
        self.try_observe_entry(entry)
            .map_err(|reason| dead_letter(entry, reason))
    }

    pub fn observe_dead_letter(&mut self, _dead_letter: &RuntimeBridgeDeadLetter) {
        self.state.dead_letter_count += 1;
    }

    pub fn state(&self) -> &RuntimeBridgeReadinessState {
        &self.state
    }

    pub fn decision(&self) -> RuntimeBridgeReadinessDecision {
        let mut reasons = Vec::new();
        let mut has_blocker = false;
        let mut has_degraded = false;

        if !self.state.health_seen {
            reasons.push(RuntimeBridgeDryReadinessReason::HealthMissing);
        } else if let Some(status) = self.state.health_status {
            if status != GatewayHealthStatus::ReadOnly {
                reasons.push(RuntimeBridgeDryReadinessReason::HealthNotReadOnly { status });
                match status {
                    GatewayHealthStatus::Degraded | GatewayHealthStatus::Stopped => {
                        has_degraded = true;
                    }
                    GatewayHealthStatus::Starting => {}
                    GatewayHealthStatus::ReadOnly => {}
                }
            }
        }

        if !self.state.gateway_readiness_seen {
            reasons.push(RuntimeBridgeDryReadinessReason::GatewayReadinessMissing);
        } else if let Some(phase) = self.state.gateway_readiness_phase {
            if phase != ReadinessPhase::Reconciliation {
                reasons.push(
                    RuntimeBridgeDryReadinessReason::GatewayReadinessNotReconciliation { phase },
                );
                match phase {
                    ReadinessPhase::Degraded | ReadinessPhase::Stopped => has_degraded = true,
                    ReadinessPhase::Blocked => has_blocker = true,
                    _ => {}
                }
            }
        }

        if !self.state.portfolio_snapshot_seen {
            reasons.push(RuntimeBridgeDryReadinessReason::PortfolioSnapshotMissing);
        }
        if !self.state.order_snapshot_seen {
            reasons.push(RuntimeBridgeDryReadinessReason::OrderSnapshotMissing);
        }
        if !self.state.market_data_seen {
            reasons.push(RuntimeBridgeDryReadinessReason::MarketDataMissing);
        }
        if self.state.blocking_unknown_orders {
            reasons.push(RuntimeBridgeDryReadinessReason::UnknownOpenOrders);
            has_blocker = true;
        }
        if self.state.dead_letter_count > 0 {
            reasons.push(RuntimeBridgeDryReadinessReason::DeadLettersPresent {
                count: self.state.dead_letter_count,
            });
            has_blocker = true;
        }

        let phase = if has_blocker {
            RuntimeBridgeDryReadinessPhase::Blocked
        } else if has_degraded {
            RuntimeBridgeDryReadinessPhase::Degraded
        } else if reasons.is_empty() {
            RuntimeBridgeDryReadinessPhase::DryReady
        } else {
            RuntimeBridgeDryReadinessPhase::WaitingForInputs
        };

        RuntimeBridgeReadinessDecision {
            schema_version: SCHEMA_VERSION,
            live_ready: false,
            phase,
            reasons,
            state: self.state.clone(),
        }
    }

    fn try_observe_entry(
        &mut self,
        entry: &RuntimeBridgeStreamEntry,
    ) -> Result<(), RuntimeBridgeDlqReason> {
        let expected = expected_message_type_for_stream(&self.config, &entry.stream)
            .ok_or(RuntimeBridgeDlqReason::UnknownStream)?;
        let envelope_value: serde_json::Value = serde_json::from_str(&entry.payload)
            .map_err(|_| RuntimeBridgeDlqReason::InvalidJson)?;
        validate_envelope_header(&envelope_value, &expected)?;

        match expected {
            MessageType::Health => {
                let envelope = decode_envelope::<GatewayHealth>(
                    &entry.payload,
                    RuntimeBridgePayloadKind::Health,
                )?;
                self.state.health_seen = true;
                self.state.health_status = Some(envelope.payload.status);
                Ok(())
            }
            MessageType::Readiness => {
                let envelope = decode_envelope::<BrokerReadiness>(
                    &entry.payload,
                    RuntimeBridgePayloadKind::Readiness,
                )?;
                self.state.gateway_readiness_seen = true;
                self.state.gateway_readiness_phase = Some(envelope.payload.phase);
                Ok(())
            }
            MessageType::PortfolioSnapshot => {
                decode_envelope::<PortfolioSnapshot>(
                    &entry.payload,
                    RuntimeBridgePayloadKind::PortfolioSnapshot,
                )?;
                self.state.portfolio_snapshot_seen = true;
                Ok(())
            }
            MessageType::OrderSnapshot => {
                let envelope = decode_envelope::<OrderSnapshot>(
                    &entry.payload,
                    RuntimeBridgePayloadKind::OrderSnapshot,
                )?;
                if order_snapshot_has_raw_comments(&envelope.payload) {
                    return Err(RuntimeBridgeDlqReason::RawOrderCommentPresent);
                }
                self.state.order_snapshot_seen = true;
                self.state.blocking_unknown_orders =
                    envelope.payload.blocking_unknown_status_present;
                Ok(())
            }
            MessageType::MarketData => {
                decode_envelope::<MarketDataEvent>(
                    &entry.payload,
                    RuntimeBridgePayloadKind::MarketData,
                )?;
                self.state.market_data_seen = true;
                Ok(())
            }
            _ => Err(RuntimeBridgeDlqReason::UnsupportedMessageType),
        }
    }
}

pub fn m3h1_adapt_runtime_shadow_entry(
    config: &RedisStreamConfig,
    entry: &RuntimeBridgeStreamEntry,
) -> M3hRuntimeShadowAdapterOutcome {
    match m3h1_try_adapt_runtime_shadow_entry(config, entry) {
        Ok(input) => M3hRuntimeShadowAdapterOutcome::Accepted(input),
        Err(reason) => M3hRuntimeShadowAdapterOutcome::DeadLetter(dead_letter(entry, reason)),
    }
}

fn m3h1_try_adapt_runtime_shadow_entry(
    config: &RedisStreamConfig,
    entry: &RuntimeBridgeStreamEntry,
) -> Result<M3hRuntimeShadowInput, RuntimeBridgeDlqReason> {
    let expected = expected_message_type_for_stream(config, &entry.stream)
        .ok_or(RuntimeBridgeDlqReason::UnknownStream)?;
    let envelope_value: serde_json::Value =
        serde_json::from_str(&entry.payload).map_err(|_| RuntimeBridgeDlqReason::InvalidJson)?;
    validate_envelope_header(&envelope_value, &expected)?;

    match expected {
        MessageType::Health => {
            decode_envelope::<GatewayHealth>(&entry.payload, RuntimeBridgePayloadKind::Health)?;
            Ok(m3h1_shadow_input(
                entry,
                M3hRuntimeShadowInputKind::Health,
                None,
                None,
                None,
            ))
        }
        MessageType::Readiness => {
            let envelope = decode_envelope::<BrokerReadiness>(
                &entry.payload,
                RuntimeBridgePayloadKind::Readiness,
            )?;
            Ok(m3h1_shadow_input(
                entry,
                M3hRuntimeShadowInputKind::Readiness,
                None,
                Some(envelope.payload.phase),
                None,
            ))
        }
        MessageType::PortfolioSnapshot => {
            decode_envelope::<PortfolioSnapshot>(
                &entry.payload,
                RuntimeBridgePayloadKind::PortfolioSnapshot,
            )?;
            Ok(m3h1_shadow_input(
                entry,
                M3hRuntimeShadowInputKind::PortfolioSnapshot,
                None,
                None,
                None,
            ))
        }
        MessageType::OrderSnapshot => {
            let envelope = decode_envelope::<OrderSnapshot>(
                &entry.payload,
                RuntimeBridgePayloadKind::OrderSnapshot,
            )?;
            if order_snapshot_has_raw_comments(&envelope.payload) {
                return Err(RuntimeBridgeDlqReason::RawOrderCommentPresent);
            }
            Ok(m3h1_shadow_input(
                entry,
                M3hRuntimeShadowInputKind::OrderSnapshot,
                None,
                None,
                Some(envelope.payload.blocking_unknown_status_present),
            ))
        }
        MessageType::MarketData => {
            let envelope = decode_envelope::<MarketDataEvent>(
                &entry.payload,
                RuntimeBridgePayloadKind::MarketData,
            )?;
            match envelope.payload {
                MarketDataEvent::Bar(bar) => {
                    let source_class = m3h1_bar_source_class(&bar);
                    let first_live_bar_unlock_candidate =
                        source_class == M3hRuntimeShadowBarSourceClass::LiveFinal;
                    let historical_or_readonly =
                        source_class == M3hRuntimeShadowBarSourceClass::HistoricalOrReadOnly;
                    Ok(m3h1_shadow_input(
                        entry,
                        M3hRuntimeShadowInputKind::BarEvent,
                        Some(M3hRuntimeShadowBarEvent {
                            bar,
                            source_class,
                            first_live_bar_unlock_candidate,
                            historical_or_readonly,
                        }),
                        None,
                        None,
                    ))
                }
                _ => Ok(m3h1_shadow_input(
                    entry,
                    M3hRuntimeShadowInputKind::NonBarMarketData,
                    None,
                    None,
                    None,
                )),
            }
        }
        _ => Err(RuntimeBridgeDlqReason::UnsupportedMessageType),
    }
}

fn m3h1_bar_source_class(bar: &Bar) -> M3hRuntimeShadowBarSourceClass {
    match (bar.source_kind, bar.is_final) {
        (MarketDataSourceKind::LiveStream, true) => M3hRuntimeShadowBarSourceClass::LiveFinal,
        (MarketDataSourceKind::LiveStream, false) => M3hRuntimeShadowBarSourceClass::LiveUpdating,
        (MarketDataSourceKind::HistoricalPoll | MarketDataSourceKind::ReadOnlyPoll, _) => {
            M3hRuntimeShadowBarSourceClass::HistoricalOrReadOnly
        }
        (MarketDataSourceKind::Recovery | MarketDataSourceKind::Unknown, _) => {
            M3hRuntimeShadowBarSourceClass::RecoveryOrUnknown
        }
    }
}

fn m3h1_shadow_input(
    entry: &RuntimeBridgeStreamEntry,
    kind: M3hRuntimeShadowInputKind,
    bar_event: Option<M3hRuntimeShadowBarEvent>,
    readiness_phase: Option<ReadinessPhase>,
    order_snapshot_unknown_orders: Option<bool>,
) -> M3hRuntimeShadowInput {
    M3hRuntimeShadowInput {
        schema_version: SCHEMA_VERSION,
        entry_id: entry.entry_id.clone(),
        kind,
        bar_event,
        readiness_phase,
        order_snapshot_unknown_orders,
        broker_neutral_payload_only: true,
        finam_dto_visible_to_runtime: false,
        emits_broker_command: false,
        runtime_live_attachment_allowed: false,
        live_ready_allowed: false,
        real_finam_order_endpoint_used: false,
        external_order_endpoint_allowed: false,
    }
}

#[derive(Debug, Clone)]
pub struct M3hRuntimeShadowConsumer {
    config: RedisStreamConfig,
    seen_bar_keys: HashSet<String>,
    last_decision_bar_open_ts: HashMap<String, DateTime<Utc>>,
    metrics: M3hRuntimeShadowConsumerMetrics,
}

impl M3hRuntimeShadowConsumer {
    pub fn new(config: RedisStreamConfig) -> Self {
        Self {
            config,
            seen_bar_keys: HashSet::new(),
            last_decision_bar_open_ts: HashMap::new(),
            metrics: M3hRuntimeShadowConsumerMetrics::default(),
        }
    }

    pub fn from_gateway_config(config: &GatewayConfig) -> Self {
        Self::new(config.redis.clone())
    }

    pub fn metrics(&self) -> &M3hRuntimeShadowConsumerMetrics {
        &self.metrics
    }

    pub fn report(&self) -> M3hRuntimeShadowConsumerReport {
        M3hRuntimeShadowConsumerReport {
            schema_version: SCHEMA_VERSION,
            metrics: self.metrics.clone(),
            watermark_restart_policy:
                M3hRuntimeShadowWatermarkRestartPolicy::EphemeralRequiresReplayOrBootstrap,
            broker_neutral_payload_only: true,
            finam_dto_visible_to_runtime: false,
            emits_broker_command: false,
            runtime_live_attachment_allowed: false,
            live_ready_allowed: false,
            real_finam_order_endpoint_used: false,
            external_order_endpoint_allowed: false,
        }
    }

    pub fn consume_entry(
        &mut self,
        entry: RuntimeBridgeStreamEntry,
    ) -> M3hRuntimeShadowConsumerOutcome {
        self.metrics.entries_seen += 1;
        match m3h1_adapt_runtime_shadow_entry(&self.config, &entry) {
            M3hRuntimeShadowAdapterOutcome::Accepted(input) => self.consume_input(input),
            M3hRuntimeShadowAdapterOutcome::DeadLetter(dead_letter) => {
                self.metrics.dead_letter_count += 1;
                M3hRuntimeShadowConsumerOutcome::DeadLetter(dead_letter)
            }
        }
    }

    fn consume_input(&mut self, input: M3hRuntimeShadowInput) -> M3hRuntimeShadowConsumerOutcome {
        if input.readiness_phase == Some(ReadinessPhase::LiveReady) {
            self.metrics.blocked_count += 1;
            self.metrics.live_ready_seen_blocked_count += 1;
            return M3hRuntimeShadowConsumerOutcome::Blocked {
                entry_id: input.entry_id,
                reason: M3hRuntimeShadowBlockedReason::InboundLiveReadyForbidden,
            };
        }

        if let Some(bar_event) = input.bar_event {
            let bar_key = m3h2_runtime_bar_key(&bar_event.bar);
            if !self.seen_bar_keys.insert(bar_key.clone()) {
                self.metrics.duplicate_bar_count += 1;
                return M3hRuntimeShadowConsumerOutcome::DuplicateBar {
                    entry_id: input.entry_id,
                    bar_key,
                };
            }
            if bar_event.source_class == M3hRuntimeShadowBarSourceClass::LiveFinal {
                let watermark_key = m3h2_runtime_watermark_key(&bar_event.bar);
                if let Some(last_open_ts) = self.last_decision_bar_open_ts.get(&watermark_key) {
                    if bar_event.bar.open_ts <= *last_open_ts {
                        self.metrics.non_decision_bar_count += 1;
                        self.metrics.non_monotonic_bar_count += 1;
                        return M3hRuntimeShadowConsumerOutcome::NonDecisionBar {
                            entry_id: input.entry_id,
                            bar_key,
                            reason: M3hRuntimeShadowNonDecisionReason::NonMonotonicLiveFinal,
                        };
                    }
                }
                self.last_decision_bar_open_ts
                    .insert(watermark_key, bar_event.bar.open_ts);
                self.metrics.strategy_decision_tick_count += 1;
                return M3hRuntimeShadowConsumerOutcome::StrategyDecisionTick {
                    entry_id: input.entry_id,
                    bar_key,
                };
            }
            self.metrics.non_decision_bar_count += 1;
            return M3hRuntimeShadowConsumerOutcome::NonDecisionBar {
                entry_id: input.entry_id,
                bar_key,
                reason: M3hRuntimeShadowNonDecisionReason::NonFinalOrNonLiveSource,
            };
        }

        self.metrics.accepted_count += 1;
        M3hRuntimeShadowConsumerOutcome::Accepted {
            kind: input.kind,
            entry_id: input.entry_id,
            strategy_decision_tick: false,
        }
    }
}

fn m3h2_runtime_watermark_key(bar: &Bar) -> String {
    format!("{}|{}", bar.instrument.symbol, bar.timeframe_sec)
}

fn m3h2_runtime_bar_key(bar: &Bar) -> String {
    format!(
        "{}|{}|{}|{}|{}|{}",
        bar.instrument.symbol,
        bar.source_kind as u8,
        bar.timeframe_sec,
        bar.open_ts.to_rfc3339_opts(SecondsFormat::Millis, true),
        bar.close_ts.to_rfc3339_opts(SecondsFormat::Millis, true),
        bar.is_final
    )
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum M3hRuntimeDryCommandLifecycleState {
    PendingEmission,
    PublishedToM3eCommandStream,
    NotEmitted,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum M3hRuntimeDryCommandNonEmissionReason {
    NoStrategyDecisionTick,
    ReadinessNotDryReady,
    LiveReadyForbidden,
    UnsafeLiveBoundary,
    UnsupportedCommandKind,
    UnsupportedOrderShape,
    DuplicateRequestId,
    PublishFailed,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct M3hRuntimeDryCommandLifecycleRecord {
    pub request_id: StrategyRequestId,
    pub command_kind: M3eCommandKind,
    pub decision_entry_id: String,
    pub decision_bar_key: String,
    pub state: M3hRuntimeDryCommandLifecycleState,
    pub non_emission_reason: Option<M3hRuntimeDryCommandNonEmissionReason>,
    pub command_stream: String,
    pub created_ts: DateTime<Utc>,
    pub updated_ts: DateTime<Utc>,
    pub publish_attempt_count: u32,
}

pub trait M3hRuntimeDryCommandLifecycleStore: Clone + Send + Sync {
    fn load_by_request_id(
        &self,
        request_id: StrategyRequestId,
    ) -> Result<Option<M3hRuntimeDryCommandLifecycleRecord>, GatewayError>;

    fn insert_new(&self, record: M3hRuntimeDryCommandLifecycleRecord)
        -> Result<bool, GatewayError>;

    fn upsert(&self, record: M3hRuntimeDryCommandLifecycleRecord) -> Result<(), GatewayError>;

    fn records(&self) -> Result<Vec<M3hRuntimeDryCommandLifecycleRecord>, GatewayError>;
}

#[derive(Debug, Default, Clone)]
pub struct M3hInMemoryRuntimeDryCommandLifecycleStore {
    records: Arc<Mutex<HashMap<StrategyRequestId, M3hRuntimeDryCommandLifecycleRecord>>>,
}

impl M3hRuntimeDryCommandLifecycleStore for M3hInMemoryRuntimeDryCommandLifecycleStore {
    fn load_by_request_id(
        &self,
        request_id: StrategyRequestId,
    ) -> Result<Option<M3hRuntimeDryCommandLifecycleRecord>, GatewayError> {
        self.records
            .lock()
            .map_err(|_| GatewayError::InternalState {
                message: "m3h runtime dry command lifecycle store mutex poisoned",
            })
            .map(|records| records.get(&request_id).cloned())
    }

    fn insert_new(
        &self,
        record: M3hRuntimeDryCommandLifecycleRecord,
    ) -> Result<bool, GatewayError> {
        let mut records = self
            .records
            .lock()
            .map_err(|_| GatewayError::InternalState {
                message: "m3h runtime dry command lifecycle store mutex poisoned",
            })?;
        if records.contains_key(&record.request_id) {
            return Ok(false);
        }
        records.insert(record.request_id, record);
        Ok(true)
    }

    fn upsert(&self, record: M3hRuntimeDryCommandLifecycleRecord) -> Result<(), GatewayError> {
        self.records
            .lock()
            .map_err(|_| GatewayError::InternalState {
                message: "m3h runtime dry command lifecycle store mutex poisoned",
            })?
            .insert(record.request_id, record);
        Ok(())
    }

    fn records(&self) -> Result<Vec<M3hRuntimeDryCommandLifecycleRecord>, GatewayError> {
        let mut records: Vec<_> = self
            .records
            .lock()
            .map_err(|_| GatewayError::InternalState {
                message: "m3h runtime dry command lifecycle store mutex poisoned",
            })?
            .values()
            .cloned()
            .collect();
        records.sort_by(|left, right| {
            left.request_id
                .to_string()
                .cmp(&right.request_id.to_string())
        });
        Ok(records)
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct M3hRuntimeDryCommandLifecycleSnapshot {
    schema_version: u16,
    records: Vec<M3hRuntimeDryCommandLifecycleRecord>,
}

#[derive(Debug, Clone)]
pub struct M3hJsonRuntimeDryCommandLifecycleStore {
    path: Arc<PathBuf>,
    inner: M3hInMemoryRuntimeDryCommandLifecycleStore,
}

impl M3hJsonRuntimeDryCommandLifecycleStore {
    pub fn open(path: impl Into<PathBuf>) -> Result<Self, GatewayError> {
        let path = path.into();
        let records = if path.exists() {
            let payload = fs::read_to_string(&path)?;
            let snapshot: M3hRuntimeDryCommandLifecycleSnapshot = serde_json::from_str(&payload)?;
            snapshot.records
        } else {
            Vec::new()
        };
        let inner = M3hInMemoryRuntimeDryCommandLifecycleStore::default();
        for record in records {
            inner.upsert(record)?;
        }
        Ok(Self {
            path: Arc::new(path),
            inner,
        })
    }

    fn persist(&self) -> Result<(), GatewayError> {
        if let Some(parent) = self.path.parent() {
            fs::create_dir_all(parent)?;
        }
        let snapshot = M3hRuntimeDryCommandLifecycleSnapshot {
            schema_version: SCHEMA_VERSION,
            records: self.inner.records()?,
        };
        let payload = serde_json::to_string_pretty(&snapshot)?;
        let tmp_path = PathBuf::from(format!("{}.tmp", self.path.to_string_lossy()));
        fs::write(&tmp_path, payload)?;
        fs::rename(tmp_path, self.path.as_ref())?;
        Ok(())
    }
}

impl M3hRuntimeDryCommandLifecycleStore for M3hJsonRuntimeDryCommandLifecycleStore {
    fn load_by_request_id(
        &self,
        request_id: StrategyRequestId,
    ) -> Result<Option<M3hRuntimeDryCommandLifecycleRecord>, GatewayError> {
        self.inner.load_by_request_id(request_id)
    }

    fn insert_new(
        &self,
        record: M3hRuntimeDryCommandLifecycleRecord,
    ) -> Result<bool, GatewayError> {
        let inserted = self.inner.insert_new(record)?;
        if inserted {
            self.persist()?;
        }
        Ok(inserted)
    }

    fn upsert(&self, record: M3hRuntimeDryCommandLifecycleRecord) -> Result<(), GatewayError> {
        self.inner.upsert(record)?;
        self.persist()
    }

    fn records(&self) -> Result<Vec<M3hRuntimeDryCommandLifecycleRecord>, GatewayError> {
        self.inner.records()
    }
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Serialize, Deserialize)]
