#[derive(Debug, Clone)]
pub struct M3hRuntimeDryCommandEmitter<S, L = M3hInMemoryRuntimeDryCommandLifecycleStore> {
    config: M3eCommandConsumerConfig,
    sink: S,
    lifecycle_store: L,
    metrics: M3hRuntimeDryCommandEmitterMetrics,
}

impl<S> M3hRuntimeDryCommandEmitter<S>
where
    S: RedisStreamSink,
{
    pub fn new(config: M3eCommandConsumerConfig, sink: S) -> Self {
        Self::new_with_store(
            config,
            sink,
            M3hInMemoryRuntimeDryCommandLifecycleStore::default(),
        )
    }

    pub fn from_gateway_config(config: &GatewayConfig, sink: S) -> Self {
        Self::new(M3eCommandConsumerConfig::from_gateway_config(config), sink)
    }
}

impl<S, L> M3hRuntimeDryCommandEmitter<S, L>
where
    S: RedisStreamSink,
    L: M3hRuntimeDryCommandLifecycleStore,
{
    pub fn new_with_store(config: M3eCommandConsumerConfig, sink: S, lifecycle_store: L) -> Self {
        Self {
            config,
            sink,
            lifecycle_store,
            metrics: M3hRuntimeDryCommandEmitterMetrics::default(),
        }
    }

    pub fn from_gateway_config_with_store(
        config: &GatewayConfig,
        sink: S,
        lifecycle_store: L,
    ) -> Self {
        Self::new_with_store(
            M3eCommandConsumerConfig::from_gateway_config(config),
            sink,
            lifecycle_store,
        )
    }

    pub fn metrics(&self) -> &M3hRuntimeDryCommandEmitterMetrics {
        &self.metrics
    }

    pub fn lifecycle_records(
        &self,
    ) -> Result<Vec<M3hRuntimeDryCommandLifecycleRecord>, GatewayError> {
        self.lifecycle_store.records()
    }

    pub fn report(&self) -> M3hRuntimeDryCommandEmitterReport {
        M3hRuntimeDryCommandEmitterReport {
            schema_version: SCHEMA_VERSION,
            metrics: self.metrics.clone(),
            command_stream: self.config.command_stream.clone(),
            m3e_command_stream_only: true,
            broker_neutral_command_envelope: true,
            dry_shadow_mode_only: true,
            runtime_live_attachment_allowed: false,
            live_ready_allowed: false,
            external_order_endpoint_allowed: false,
            real_finam_order_endpoint_used: false,
            stop_sltp_bracket_replace_multileg_allowed: false,
        }
    }

    pub async fn emit_candidate(
        &mut self,
        decision: &M3hRuntimeShadowConsumerOutcome,
        readiness: &RuntimeBridgeReadinessDecision,
        candidate: M3hRuntimeDryCommandCandidate,
        now: DateTime<Utc>,
    ) -> Result<M3hRuntimeDryCommandEmitOutcome, GatewayError> {
        self.metrics.candidates_seen += 1;
        let request_id = command_request_id(&candidate.command);
        let command_kind = command_kind(&candidate.command);

        let (decision_entry_id, decision_bar_key) = match decision {
            M3hRuntimeShadowConsumerOutcome::StrategyDecisionTick { entry_id, bar_key } => {
                (entry_id.clone(), bar_key.clone())
            }
            _ => {
                self.metrics.non_emitted_count += 1;
                self.record_not_emitted(
                    &candidate,
                    M3hRuntimeDryCommandNonEmissionReason::NoStrategyDecisionTick,
                    now,
                    None,
                    None,
                )?;
                return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                    request_id: Some(request_id),
                    reason: M3hRuntimeDryCommandNonEmissionReason::NoStrategyDecisionTick,
                    pending_state_preserved: false,
                });
            }
        };

        if readiness.live_ready {
            self.metrics.non_emitted_count += 1;
            self.record_not_emitted(
                &candidate,
                M3hRuntimeDryCommandNonEmissionReason::LiveReadyForbidden,
                now,
                Some(decision_entry_id),
                Some(decision_bar_key),
            )?;
            return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                request_id: Some(request_id),
                reason: M3hRuntimeDryCommandNonEmissionReason::LiveReadyForbidden,
                pending_state_preserved: false,
            });
        }
        if readiness.phase != RuntimeBridgeDryReadinessPhase::DryReady {
            self.metrics.non_emitted_count += 1;
            self.record_not_emitted(
                &candidate,
                M3hRuntimeDryCommandNonEmissionReason::ReadinessNotDryReady,
                now,
                Some(decision_entry_id),
                Some(decision_bar_key),
            )?;
            return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                request_id: Some(request_id),
                reason: M3hRuntimeDryCommandNonEmissionReason::ReadinessNotDryReady,
                pending_state_preserved: false,
            });
        }
        if candidate.runtime_live_attachment_allowed
            || candidate.live_ready_allowed
            || candidate.external_order_endpoint_allowed
            || candidate.real_finam_order_endpoint_used
            || candidate.stop_sltp_bracket_replace_multileg_requested
        {
            self.metrics.non_emitted_count += 1;
            self.record_not_emitted(
                &candidate,
                M3hRuntimeDryCommandNonEmissionReason::UnsafeLiveBoundary,
                now,
                Some(decision_entry_id),
                Some(decision_bar_key),
            )?;
            return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                request_id: Some(request_id),
                reason: M3hRuntimeDryCommandNonEmissionReason::UnsafeLiveBoundary,
                pending_state_preserved: false,
            });
        }
        if decision_entry_id != candidate.decision_entry_id
            || decision_bar_key != candidate.decision_bar_key
        {
            self.metrics.non_emitted_count += 1;
            self.record_not_emitted(
                &candidate,
                M3hRuntimeDryCommandNonEmissionReason::NoStrategyDecisionTick,
                now,
                Some(decision_entry_id),
                Some(decision_bar_key),
            )?;
            return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                request_id: Some(request_id),
                reason: M3hRuntimeDryCommandNonEmissionReason::NoStrategyDecisionTick,
                pending_state_preserved: false,
            });
        }
        if !m3h3_runtime_dry_command_shape_supported(&candidate.command) {
            self.metrics.non_emitted_count += 1;
            self.record_not_emitted(
                &candidate,
                M3hRuntimeDryCommandNonEmissionReason::UnsupportedOrderShape,
                now,
                Some(decision_entry_id),
                Some(decision_bar_key),
            )?;
            return Ok(M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                request_id: Some(request_id),
                reason: M3hRuntimeDryCommandNonEmissionReason::UnsupportedOrderShape,
                pending_state_preserved: false,
            });
        }
        if let Some(existing) = self.lifecycle_store.load_by_request_id(request_id)? {
            self.metrics.duplicate_request_count += 1;
            self.metrics.non_emitted_count += 1;
            return Ok(M3hRuntimeDryCommandEmitOutcome::DuplicateRequest {
                request_id,
                state: existing.state,
            });
        }

        let mut record = M3hRuntimeDryCommandLifecycleRecord {
            request_id,
            command_kind,
            decision_entry_id,
            decision_bar_key,
            state: M3hRuntimeDryCommandLifecycleState::PendingEmission,
            non_emission_reason: None,
            command_stream: self.config.command_stream.clone(),
            created_ts: now,
            updated_ts: now,
            publish_attempt_count: 0,
        };
        if !self.lifecycle_store.insert_new(record.clone())? {
            self.metrics.duplicate_request_count += 1;
            self.metrics.non_emitted_count += 1;
            let existing = self
                .lifecycle_store
                .load_by_request_id(request_id)?
                .expect("existing lifecycle record after duplicate insert");
            return Ok(M3hRuntimeDryCommandEmitOutcome::DuplicateRequest {
                request_id,
                state: existing.state,
            });
        }
        self.metrics.pending_record_count += 1;

        let envelope = Envelope::new(
            self.config.source.clone(),
            MessageType::Command,
            candidate.command,
        );
        record.publish_attempt_count = record.publish_attempt_count.saturating_add(1);
        if let Err(error) = self
            .sink
            .publish_json(&self.config.command_stream, &envelope, None)
            .await
        {
            record.state = M3hRuntimeDryCommandLifecycleState::NotEmitted;
            record.non_emission_reason = Some(M3hRuntimeDryCommandNonEmissionReason::PublishFailed);
            record.updated_ts = now;
            self.lifecycle_store.upsert(record)?;
            self.metrics.non_emitted_count += 1;
            self.metrics.publish_failed_count += 1;
            return Err(error);
        }

        record.state = M3hRuntimeDryCommandLifecycleState::PublishedToM3eCommandStream;
        record.updated_ts = now;
        self.lifecycle_store.upsert(record)?;
        self.metrics.dry_command_published_count += 1;
        self.metrics.broker_command_emitted_count += 1;
        Ok(M3hRuntimeDryCommandEmitOutcome::CommandPublished {
            request_id,
            command_kind,
            stream: self.config.command_stream.clone(),
            state: M3hRuntimeDryCommandLifecycleState::PublishedToM3eCommandStream,
        })
    }

    fn record_not_emitted(
        &self,
        candidate: &M3hRuntimeDryCommandCandidate,
        reason: M3hRuntimeDryCommandNonEmissionReason,
        now: DateTime<Utc>,
        decision_entry_id: Option<String>,
        decision_bar_key: Option<String>,
    ) -> Result<(), GatewayError> {
        let request_id = command_request_id(&candidate.command);
        if self
            .lifecycle_store
            .load_by_request_id(request_id)?
            .is_some()
        {
            return Ok(());
        }
        self.lifecycle_store
            .insert_new(M3hRuntimeDryCommandLifecycleRecord {
                request_id,
                command_kind: command_kind(&candidate.command),
                decision_entry_id: decision_entry_id
                    .unwrap_or_else(|| candidate.decision_entry_id.clone()),
                decision_bar_key: decision_bar_key
                    .unwrap_or_else(|| candidate.decision_bar_key.clone()),
                state: M3hRuntimeDryCommandLifecycleState::NotEmitted,
                non_emission_reason: Some(reason),
                command_stream: self.config.command_stream.clone(),
                created_ts: now,
                updated_ts: now,
                publish_attempt_count: 0,
            })?;
        Ok(())
    }
}

fn m3h3_runtime_dry_command_shape_supported(command: &BrokerCommand) -> bool {
    match command {
        BrokerCommand::PlaceOrder(order) => {
            matches!(
                order.order_type,
                broker_core::order::OrderType::Market | broker_core::order::OrderType::Limit
            ) && order.comment.is_none()
        }
        BrokerCommand::CancelOrder(_) => false,
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct M3h5ShadowReplayReport {
    pub schema_version: u16,
    pub generated_at: DateTime<Utc>,
    pub m3h_runtime_shadow_stage_closed: bool,
    pub stage_closure_report: bool,
    pub end_to_end_dry_path_to_m3e_ack: bool,
    pub decision_tick_accounting_ok: bool,
    pub runtime_shadow_replay_ok: bool,
    pub dry_command_report_redacted: bool,
    pub pending_emission_operator_visibility_ok: bool,
    pub decision_tick_count: u64,
    pub dry_command_published_count: u64,
    pub duplicate_request_id_count: u64,
    pub not_emitted_count: u64,
    pub pending_emission_count: u64,
    pub oldest_pending_emission_age_ms: Option<i64>,
    pub pending_request_hashes: Vec<String>,
    pub maybe_published_not_finalized_count: u64,
    pub not_ready_suppression_count: u64,
    pub inbound_live_ready_blocked_count: u64,
    pub bar_duplicate_count: u64,
    pub bar_non_monotonic_count: u64,
    pub m3e_dry_ack_count: u64,
    pub m3e_duplicate_ack_count: u64,
    pub runtime_live_attachment_allowed: bool,
    pub live_ready_allowed: bool,
    pub external_order_endpoint_allowed: bool,
    pub real_finam_order_endpoint_used: bool,
    pub stop_sltp_bracket_replace_multileg_allowed: bool,
    pub raw_request_ids_exported: bool,
    pub raw_payload_exported: bool,
    pub raw_token_exported: bool,
    pub raw_body_exported: bool,
    pub m3e_command_stream_only: bool,
}

#[derive(Debug, Clone)]
pub struct M3h5ShadowReplayReportInput {
    pub runtime_consumer_report: M3hRuntimeShadowConsumerReport,
    pub dry_emitter_report: M3hRuntimeDryCommandEmitterReport,
    pub lifecycle_records: Vec<M3hRuntimeDryCommandLifecycleRecord>,
    pub m3e_report: Option<M3eCommandConsumerDurableReport>,
    pub now: DateTime<Utc>,
}

pub fn m3h5_shadow_replay_report(input: M3h5ShadowReplayReportInput) -> M3h5ShadowReplayReport {
    let pending_records: Vec<_> = input
        .lifecycle_records
        .iter()
        .filter(|record| record.state == M3hRuntimeDryCommandLifecycleState::PendingEmission)
        .collect();
    let oldest_pending_emission_age_ms = pending_records
        .iter()
        .map(|record| (input.now - record.created_ts).num_milliseconds())
        .max();
    let pending_request_hashes = pending_records
        .iter()
        .map(|record| m3h5_redacted_request_hash(record.request_id))
        .collect::<Vec<_>>();
    let m3e_dry_ack_count = input.m3e_report.as_ref().is_some_and(|report| {
        report.ack_status == Some(CommandAckStatus::Rejected)
            && report.ack_reason_code == Some(CommandAckReasonCode::DryRunOnly)
            && !report.endpoint_transport_invoked
            && !report.external_order_endpoint_allowed
    }) as u64;
    let m3e_duplicate_ack_count = input
        .m3e_report
        .as_ref()
        .is_some_and(|report| report.ack_status == Some(CommandAckStatus::Duplicate))
        as u64;
    let dry_command_report_redacted = input.m3e_report.as_ref().map_or(true, |report| {
        !report.raw_payload_exported
            && !report.raw_token_exported
            && !report.raw_body_exported
            && !report.raw_command_comment_exported
    });
    let no_live_boundary = !input.dry_emitter_report.runtime_live_attachment_allowed
        && !input.dry_emitter_report.live_ready_allowed
        && !input.dry_emitter_report.external_order_endpoint_allowed
        && !input.dry_emitter_report.real_finam_order_endpoint_used
        && !input
            .dry_emitter_report
            .stop_sltp_bracket_replace_multileg_allowed
        && !input
            .runtime_consumer_report
            .runtime_live_attachment_allowed
        && !input.runtime_consumer_report.live_ready_allowed
        && !input
            .runtime_consumer_report
            .external_order_endpoint_allowed
        && !input.runtime_consumer_report.real_finam_order_endpoint_used;
    let decision_tick_count = input
        .runtime_consumer_report
        .metrics
        .strategy_decision_tick_count;
    let accounted_decision_count = input.dry_emitter_report.metrics.dry_command_published_count
        + input.dry_emitter_report.metrics.non_emitted_count
        + input.dry_emitter_report.metrics.duplicate_request_count;
    let decision_tick_accounting_ok = decision_tick_count == accounted_decision_count;
    let end_to_end_dry_path_to_m3e_ack =
        input.dry_emitter_report.metrics.dry_command_published_count > 0 && m3e_dry_ack_count > 0;
    let runtime_shadow_replay_ok = decision_tick_accounting_ok
        && input.dry_emitter_report.m3e_command_stream_only
        && no_live_boundary;
    let pending_emission_operator_visibility_ok =
        pending_records.is_empty() || oldest_pending_emission_age_ms.is_some();
    let stage_closure_report = end_to_end_dry_path_to_m3e_ack
        && decision_tick_accounting_ok
        && dry_command_report_redacted
        && pending_emission_operator_visibility_ok
        && input.dry_emitter_report.m3e_command_stream_only
        && no_live_boundary;
    let not_ready_suppression_count = input
        .lifecycle_records
        .iter()
        .filter(|record| {
            record.non_emission_reason
                == Some(M3hRuntimeDryCommandNonEmissionReason::ReadinessNotDryReady)
        })
        .count() as u64;
    let report = M3h5ShadowReplayReport {
        schema_version: SCHEMA_VERSION,
        generated_at: input.now,
        m3h_runtime_shadow_stage_closed: false,
        stage_closure_report,
        end_to_end_dry_path_to_m3e_ack,
        decision_tick_accounting_ok,
        runtime_shadow_replay_ok,
        dry_command_report_redacted,
        pending_emission_operator_visibility_ok,
        decision_tick_count,
        dry_command_published_count: input.dry_emitter_report.metrics.dry_command_published_count,
        duplicate_request_id_count: input.dry_emitter_report.metrics.duplicate_request_count,
        not_emitted_count: input.dry_emitter_report.metrics.non_emitted_count,
        pending_emission_count: pending_records.len() as u64,
        oldest_pending_emission_age_ms,
        pending_request_hashes,
        maybe_published_not_finalized_count: pending_records.len() as u64,
        not_ready_suppression_count,
        inbound_live_ready_blocked_count: input
            .runtime_consumer_report
            .metrics
            .live_ready_seen_blocked_count,
        bar_duplicate_count: input.runtime_consumer_report.metrics.duplicate_bar_count,
        bar_non_monotonic_count: input
            .runtime_consumer_report
            .metrics
            .non_monotonic_bar_count,
        m3e_dry_ack_count,
        m3e_duplicate_ack_count,
        runtime_live_attachment_allowed: false,
        live_ready_allowed: false,
        external_order_endpoint_allowed: false,
        real_finam_order_endpoint_used: false,
        stop_sltp_bracket_replace_multileg_allowed: false,
        raw_request_ids_exported: false,
        raw_payload_exported: false,
        raw_token_exported: false,
        raw_body_exported: false,
        m3e_command_stream_only: input.dry_emitter_report.m3e_command_stream_only,
    };
    M3h5ShadowReplayReport {
        m3h_runtime_shadow_stage_closed: report.stage_closure_report,
        ..report
    }
}

fn m3h5_redacted_request_hash(request_id: StrategyRequestId) -> String {
    let mut hasher = Sha256::new();
    hasher.update(request_id.to_string().as_bytes());
    let digest = hasher.finalize();
    format!("sha256:{digest:x}")
}

