pub fn classify_cancel_broker_truth(
    observation: &CancelBrokerTruthObservation,
    checked_ts: DateTime<Utc>,
) -> CancelBrokerTruthClassification {
    let age_ms = checked_ts
        .signed_duration_since(observation.observed_ts)
        .num_milliseconds()
        .try_into()
        .ok();
    let stale = match age_ms {
        Some(age_ms) => age_ms > observation.max_age_ms,
        None => true,
    };
    let status_class = if stale {
        CancelBrokerTruthStatusClass::Unknown
    } else {
        observation.status_class()
    };
    let broker_truth = match status_class {
        CancelBrokerTruthStatusClass::Terminal => CancelReconciliationBrokerTruth::Terminal,
        CancelBrokerTruthStatusClass::StillWorking => CancelReconciliationBrokerTruth::StillWorking,
        CancelBrokerTruthStatusClass::Unknown => CancelReconciliationBrokerTruth::Unknown,
    };
    let operator_disarm_signal = match (stale, broker_truth) {
        (true, _) => Some(OperatorDisarmSignal::ReconciliationStale),
        (false, CancelReconciliationBrokerTruth::Unknown) => {
            Some(OperatorDisarmSignal::UnknownPendingOrder)
        }
        (false, _) => None,
    };

    CancelBrokerTruthClassification {
        broker_truth,
        diagnostic: CancelBrokerTruthDiagnostic {
            source: observation.source,
            order_id_present: observation.order_id_present,
            order_id_len: observation.order_id_len,
            client_order_id_present: observation.client_order_id_present,
            client_order_id_len: observation.client_order_id_len,
            identity_strength: observation.identity_strength,
            evidence_present: observation.evidence_present,
            status_present: observation.order_status.is_some(),
            status_class,
            stale,
            age_ms,
            max_age_ms: observation.max_age_ms,
        },
        operator_disarm_signal,
    }
}

pub fn build_cancel_truth_from_get_order(
    order: Option<&Order>,
    observed_ts: DateTime<Utc>,
    freshness_policy: &CancelBrokerTruthFreshnessPolicy,
) -> CancelBrokerTruthObservation {
    let max_age_ms = freshness_policy.max_age_ms(CancelBrokerTruthSource::GetOrder);
    order.map_or_else(
        || {
            CancelBrokerTruthObservation::missing(
                CancelBrokerTruthSource::GetOrder,
                observed_ts,
                max_age_ms,
            )
        },
        |order| {
            CancelBrokerTruthObservation::from_order(
                CancelBrokerTruthSource::GetOrder,
                order,
                max_age_ms,
            )
            .with_observed_ts(observed_ts)
        },
    )
}

pub fn build_cancel_truth_from_get_order_response(
    order: Option<&Order>,
    order_id: &BrokerOrderId,
    client_order_id: Option<&ClientOrderId>,
    observed_ts: DateTime<Utc>,
    freshness_policy: &CancelBrokerTruthFreshnessPolicy,
) -> CancelBrokerTruthFetchResult {
    match order {
        Some(order) => match order_cancel_identity_strength(order, order_id, client_order_id) {
            Some(identity_strength) => {
                let mut observation =
                    build_cancel_truth_from_get_order(Some(order), observed_ts, freshness_policy);
                observation.identity_strength = Some(identity_strength);
                CancelBrokerTruthFetchResult::observation(observation)
            }
            None => CancelBrokerTruthFetchResult::missing(
                CancelBrokerTruthSource::GetOrder,
                CancelBrokerTruthFetchReason::MismatchedOrderIdentity,
                observed_ts,
            ),
        },
        None => CancelBrokerTruthFetchResult::missing(
            CancelBrokerTruthSource::GetOrder,
            CancelBrokerTruthFetchReason::NotFound404,
            observed_ts,
        ),
    }
}

pub fn build_cancel_truth_from_orders_snapshot(
    orders: &[Order],
    order_id: &BrokerOrderId,
    client_order_id: Option<&ClientOrderId>,
    snapshot_received_ts: DateTime<Utc>,
    freshness_policy: &CancelBrokerTruthFreshnessPolicy,
) -> CancelBrokerTruthObservation {
    let max_age_ms = freshness_policy.max_age_ms(CancelBrokerTruthSource::OrdersSnapshot);
    orders
        .iter()
        .find(|order| order_matches_cancel(order, order_id, client_order_id))
        .map_or_else(
            || {
                CancelBrokerTruthObservation::missing(
                    CancelBrokerTruthSource::OrdersSnapshot,
                    snapshot_received_ts,
                    max_age_ms,
                )
            },
            |order| {
                CancelBrokerTruthObservation::from_order(
                    CancelBrokerTruthSource::OrdersSnapshot,
                    order,
                    max_age_ms,
                )
                .with_observed_ts(snapshot_received_ts)
            },
        )
}

pub fn build_cancel_truth_from_trades_snapshot(
    trades: &[Trade],
    order_id: &BrokerOrderId,
    client_order_id: Option<&ClientOrderId>,
    snapshot_received_ts: DateTime<Utc>,
    freshness_policy: &CancelBrokerTruthFreshnessPolicy,
) -> CancelBrokerTruthObservation {
    let max_age_ms = freshness_policy.max_age_ms(CancelBrokerTruthSource::TradesSnapshot);
    trades
        .iter()
        .filter(|trade| trade_matches_cancel(trade, order_id, client_order_id))
        .max_by_key(|trade| trade.received_ts)
        .map_or_else(
            || {
                CancelBrokerTruthObservation::missing(
                    CancelBrokerTruthSource::TradesSnapshot,
                    snapshot_received_ts,
                    max_age_ms,
                )
            },
            |trade| {
                CancelBrokerTruthObservation::from_trade(trade, max_age_ms)
                    .with_observed_ts(snapshot_received_ts)
            },
        )
}

pub fn build_cancel_truth_from_position_snapshot(
    positions: &[Position],
    instrument: &InstrumentId,
    snapshot_received_ts: DateTime<Utc>,
    freshness_policy: &CancelBrokerTruthFreshnessPolicy,
) -> CancelBrokerTruthObservation {
    let max_age_ms = freshness_policy.max_age_ms(CancelBrokerTruthSource::PositionSnapshot);
    positions
        .iter()
        .find(|position| &position.instrument == instrument)
        .map_or_else(
            || {
                CancelBrokerTruthObservation::missing(
                    CancelBrokerTruthSource::PositionSnapshot,
                    snapshot_received_ts,
                    max_age_ms,
                )
            },
            |position| {
                CancelBrokerTruthObservation::from_position(
                    position,
                    snapshot_received_ts,
                    max_age_ms,
                )
            },
        )
}

pub fn reconcile_cancel_broker_truth_sources(
    classifications: &[CancelBrokerTruthClassification],
    precedence_policy: &CancelBrokerTruthPrecedencePolicy,
) -> CancelBrokerTruthReconciliationDecision {
    let diagnostics = classifications
        .iter()
        .map(|classification| classification.diagnostic.clone())
        .collect::<Vec<_>>();
    let stale_present = diagnostics.iter().any(|diagnostic| diagnostic.stale);
    let unknown_present = classifications.iter().any(|classification| {
        classification.broker_truth == CancelReconciliationBrokerTruth::Unknown
    });
    let fresh_known = classifications
        .iter()
        .filter(|classification| {
            !classification.diagnostic.stale
                && classification.broker_truth != CancelReconciliationBrokerTruth::Unknown
        })
        .collect::<Vec<_>>();
    let terminal_present = fresh_known.iter().any(|classification| {
        classification.broker_truth == CancelReconciliationBrokerTruth::Terminal
    });
    let still_working_present = fresh_known.iter().any(|classification| {
        classification.broker_truth == CancelReconciliationBrokerTruth::StillWorking
    });

    if terminal_present && still_working_present {
        let mut conflicting_sources = fresh_known
            .iter()
            .map(|classification| classification.diagnostic.source)
            .collect::<Vec<_>>();
        conflicting_sources.sort_by_key(|source| precedence_policy.rank(*source));
        conflicting_sources.dedup();
        return CancelBrokerTruthReconciliationDecision {
            broker_truth: CancelReconciliationBrokerTruth::Unknown,
            decision_kind: CancelBrokerTruthDecisionKind::Conflict,
            selected_source: None,
            diagnostics,
            stale_present,
            unknown_present,
            conflicting_sources,
            operator_disarm_signal: Some(OperatorDisarmSignal::ReconciliationConflict),
        };
    }

    if let Some(selected) = fresh_known
        .into_iter()
        .min_by_key(|classification| precedence_policy.rank(classification.diagnostic.source))
    {
        return CancelBrokerTruthReconciliationDecision {
            broker_truth: selected.broker_truth,
            decision_kind: CancelBrokerTruthDecisionKind::Selected,
            selected_source: Some(selected.diagnostic.source),
            diagnostics,
            stale_present,
            unknown_present,
            conflicting_sources: Vec::new(),
            operator_disarm_signal: None,
        };
    }

    let selected_source = classifications
        .iter()
        .min_by_key(|classification| precedence_policy.rank(classification.diagnostic.source))
        .map(|classification| classification.diagnostic.source);
    CancelBrokerTruthReconciliationDecision {
        broker_truth: CancelReconciliationBrokerTruth::Unknown,
        decision_kind: CancelBrokerTruthDecisionKind::UnknownOnly,
        selected_source,
        diagnostics,
        stale_present,
        unknown_present,
        conflicting_sources: Vec::new(),
        operator_disarm_signal: Some(if stale_present {
            OperatorDisarmSignal::ReconciliationStale
        } else {
            OperatorDisarmSignal::UnknownPendingOrder
        }),
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum CancelBrokerTruthFetchReason {
    NotFound404,
    Timeout,
    DecodeError,
    Maintenance,
    Unauthorized,
    RateLimited,
    InvalidRequest,
    UnsupportedEndpoint,
    UnknownClientError,
    MismatchedOrderIdentity,
    AccountMismatch,
    InstrumentMismatch,
    WeakIdentityNeedsConfirmation,
    TradesSnapshotIncomplete,
    NotRequested,
    MissingFixture,
    PositionGuardRejected,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum CancelBrokerTruthFetchOutcomeKind {
    Evidence,
    Missing,
    Error,
    GuardRejected,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum CancelBrokerTruthReadonlyFailure {
    HttpStatus(u16),
    Timeout,
    DecodeError,
    MissingFixture,
}

pub fn map_cancel_broker_truth_readonly_failure_to_fetch_reason(
    failure: CancelBrokerTruthReadonlyFailure,
) -> CancelBrokerTruthFetchReason {
    match failure {
        CancelBrokerTruthReadonlyFailure::HttpStatus(404) => {
            CancelBrokerTruthFetchReason::NotFound404
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(401 | 403) => {
            CancelBrokerTruthFetchReason::Unauthorized
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(408 | 504) => {
            CancelBrokerTruthFetchReason::Timeout
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(429) => {
            CancelBrokerTruthFetchReason::RateLimited
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(400 | 422) => {
            CancelBrokerTruthFetchReason::InvalidRequest
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(405) => {
            CancelBrokerTruthFetchReason::UnsupportedEndpoint
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(409 | 410) => {
            CancelBrokerTruthFetchReason::UnknownClientError
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(400..=499) => {
            CancelBrokerTruthFetchReason::UnknownClientError
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(500..=599) => {
            CancelBrokerTruthFetchReason::Maintenance
        }
        CancelBrokerTruthReadonlyFailure::HttpStatus(_) => {
            CancelBrokerTruthFetchReason::DecodeError
        }
        CancelBrokerTruthReadonlyFailure::Timeout => CancelBrokerTruthFetchReason::Timeout,
        CancelBrokerTruthReadonlyFailure::DecodeError => CancelBrokerTruthFetchReason::DecodeError,
        CancelBrokerTruthReadonlyFailure::MissingFixture => {
            CancelBrokerTruthFetchReason::MissingFixture
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub struct CancelPositionTruthGuardPolicy {
    pub require_instrument_match: bool,
    pub require_intent_context: bool,
    pub require_expected_position_delta: bool,
    pub require_strategy_state: bool,
    pub require_order_or_trade_absent_or_stale: bool,
}

impl Default for CancelPositionTruthGuardPolicy {
    fn default() -> Self {
        Self {
            require_instrument_match: true,
            require_intent_context: true,
            require_expected_position_delta: true,
            require_strategy_state: true,
            require_order_or_trade_absent_or_stale: true,
        }
    }
}

impl CancelPositionTruthGuardPolicy {
    fn allows_terminal(&self, context: &CancelPositionTruthGuardContext) -> bool {
        (!self.require_instrument_match || context.instrument_match)
            && (!self.require_intent_context || context.intent_context_present)
            && (!self.require_expected_position_delta || context.expected_position_delta_present)
            && (!self.require_strategy_state || context.strategy_state_known)
            && (!self.require_order_or_trade_absent_or_stale
                || context.order_or_trade_evidence_absent_or_stale)
    }
}

