#[derive(Clone, PartialEq, Eq)]
pub struct CancelBrokerTruthReadonlyHttpResponse {
    status: u16,
    body: Option<Vec<u8>>,
    transport_error_category: Option<FinamRealReadonlyTransportErrorCategory>,
}

impl std::fmt::Debug for CancelBrokerTruthReadonlyHttpResponse {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        formatter
            .debug_struct("CancelBrokerTruthReadonlyHttpResponse")
            .field("diagnostic", &self.diagnostic())
            .finish()
    }
}

impl CancelBrokerTruthReadonlyHttpResponse {
    pub fn empty(status: u16) -> Self {
        Self {
            status,
            body: None,
            transport_error_category: None,
        }
    }

    pub fn empty_with_transport_error(
        status: u16,
        transport_error_category: FinamRealReadonlyTransportErrorCategory,
    ) -> Self {
        Self {
            status,
            body: None,
            transport_error_category: Some(transport_error_category),
        }
    }

    pub fn json<T>(status: u16, body: &T) -> Self
    where
        T: Serialize,
    {
        Self {
            status,
            body: Some(
                serde_json::to_vec(body)
                    .expect("local read-only broker-truth fixture body is serializable"),
            ),
            transport_error_category: None,
        }
    }

    pub fn raw(status: u16, body: impl Into<Vec<u8>>) -> Self {
        Self {
            status,
            body: Some(body.into()),
            transport_error_category: None,
        }
    }

    pub fn diagnostic(&self) -> CancelBrokerTruthReadonlyHttpDiagnostic {
        self.diagnostic_with_transport(false, false)
    }

    fn diagnostic_with_transport(
        &self,
        actual_http_send_started: bool,
        actual_http_send_completed: bool,
    ) -> CancelBrokerTruthReadonlyHttpDiagnostic {
        self.diagnostic_with_transport_timing(
            actual_http_send_started,
            actual_http_send_completed,
            None,
            None,
            None,
        )
    }

    fn diagnostic_with_transport_timing(
        &self,
        actual_http_send_started: bool,
        actual_http_send_completed: bool,
        actual_http_send_started_at: Option<DateTime<Utc>>,
        actual_http_send_completed_at: Option<DateTime<Utc>>,
        actual_http_send_elapsed_ms: Option<u64>,
    ) -> CancelBrokerTruthReadonlyHttpDiagnostic {
        CancelBrokerTruthReadonlyHttpDiagnostic {
            status: self.status,
            body_present: self.body.is_some(),
            body_len: self.body.as_ref().map(Vec::len),
            body_sha256: self.body.as_ref().map(|body| sha256_hex(body)),
            transport_error_category: self.transport_error_category,
            actual_http_send_started,
            actual_http_send_completed,
            actual_http_send_started_at,
            actual_http_send_completed_at,
            actual_http_send_elapsed_ms,
        }
    }
}

