#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct FinamRealReadonlyTokenAccountPreflightDiagnostic {
    pub request_snapshot_fingerprint: String,
    pub preflight_checked_at: DateTime<Utc>,
    pub preflight_max_age_ms: u64,
    pub token_details_checked: bool,
    pub token_readonly_flag_present: bool,
    pub token_readonly_flag_value: Option<bool>,
    pub md_permissions_count: usize,
    pub token_account_ids_count: usize,
    pub requested_account_id_present: bool,
    pub requested_account_id_len: Option<usize>,
    pub requested_account_id_sha256: Option<String>,
    pub token_account_hash_match: Option<bool>,
    pub no_order_feature_flags_enabled: bool,
}

impl FinamRealReadonlyTokenAccountPreflightDiagnostic {
    pub fn from_token_details(
        features: &GatewayFeatureSet,
        request: &CancelBrokerTruthFetchRequestSnapshot,
        token_details: Option<&broker_finam::dto::TokenDetailsResponse>,
        preflight_checked_at: DateTime<Utc>,
        preflight_max_age_ms: u64,
    ) -> Self {
        let request_diagnostic =
            CancelBrokerTruthFetchRequestRedactedDiagnostic::from_snapshot(request);
        let requested_account_id_len = request
            .account_id
            .as_ref()
            .map(|account_id| account_id.as_str().len());
        let requested_account_id_sha256 = request
            .account_id
            .as_ref()
            .map(|account_id| sha256_hex(account_id.as_str().as_bytes()));
        let token_account_hash_match = token_details.zip(requested_account_id_sha256.as_ref()).map(
            |(details, requested_hash)| {
                details
                    .account_ids
                    .iter()
                    .any(|account_id| sha256_hex(account_id.as_bytes()) == *requested_hash)
            },
        );
        Self {
            request_snapshot_fingerprint: request_diagnostic.request_snapshot_fingerprint,
            preflight_checked_at,
            preflight_max_age_ms,
            token_details_checked: token_details.is_some(),
            token_readonly_flag_present: token_details
                .and_then(|details| details.readonly)
                .is_some(),
            token_readonly_flag_value: token_details.and_then(|details| details.readonly),
            md_permissions_count: token_details
                .map(|details| details.md_permissions.len())
                .unwrap_or_default(),
            token_account_ids_count: token_details
                .map(|details| details.account_ids.len())
                .unwrap_or_default(),
            requested_account_id_present: request.account_id.is_some(),
            requested_account_id_len,
            requested_account_id_sha256,
            token_account_hash_match,
            no_order_feature_flags_enabled: !features.command_consumer_enabled
                && !features.order_placement_enabled
                && !features.cancel_enabled
                && !features.stop_sltp_bracket_enabled,
        }
    }

    fn allows_operator_probe(&self) -> bool {
        self.token_details_checked
            && self.token_readonly_flag_value == Some(true)
            && self.requested_account_id_present
            && self.token_account_hash_match == Some(true)
            && self.no_order_feature_flags_enabled
    }
}

#[derive(Clone, PartialEq, Eq)]
pub struct FinamRealReadonlyTokenAccountPreflightApproved {
    diagnostic: FinamRealReadonlyTokenAccountPreflightDiagnostic,
    request_diagnostic: CancelBrokerTruthFetchRequestRedactedDiagnostic,
    _private: (),
}

impl std::fmt::Debug for FinamRealReadonlyTokenAccountPreflightApproved {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        formatter
            .debug_struct("FinamRealReadonlyTokenAccountPreflightApproved")
            .field("diagnostic", &self.diagnostic)
            .field("request_diagnostic", &self.request_diagnostic)
            .finish()
    }
}

impl FinamRealReadonlyTokenAccountPreflightApproved {
    pub fn try_from_token_details(
        features: &GatewayFeatureSet,
        request: &CancelBrokerTruthFetchRequestSnapshot,
        token_details: &broker_finam::dto::TokenDetailsResponse,
        preflight_checked_at: DateTime<Utc>,
        preflight_max_age_ms: u64,
    ) -> Result<Self, FinamRealReadonlyTokenAccountPreflightApprovalError> {
        let diagnostic = FinamRealReadonlyTokenAccountPreflightDiagnostic::from_token_details(
            features,
            request,
            Some(token_details),
            preflight_checked_at,
            preflight_max_age_ms,
        );
        if diagnostic.allows_operator_probe() {
            Ok(Self {
                diagnostic,
                request_diagnostic: CancelBrokerTruthFetchRequestRedactedDiagnostic::from_snapshot(
                    request,
                ),
                _private: (),
            })
        } else {
            Err(
                FinamRealReadonlyTokenAccountPreflightApprovalError::Blocked {
                    diagnostic: Box::new(diagnostic),
                },
            )
        }
    }

    pub fn diagnostic(&self) -> &FinamRealReadonlyTokenAccountPreflightDiagnostic {
        &self.diagnostic
    }

    pub fn request_diagnostic(&self) -> &CancelBrokerTruthFetchRequestRedactedDiagnostic {
        &self.request_diagnostic
    }

    fn allows_request(&self, request: &CancelBrokerTruthFetchRequestSnapshot) -> bool {
        self.request_diagnostic.matches_snapshot(request)
    }

    fn is_fresh_at(&self, observed_at: DateTime<Utc>) -> bool {
        self.computed_age_ms_at(observed_at)
            .is_some_and(|age_ms| (age_ms as u64) <= self.diagnostic.preflight_max_age_ms)
    }

    fn computed_age_ms_at(&self, observed_at: DateTime<Utc>) -> Option<i64> {
        if self.diagnostic.preflight_max_age_ms == 0 {
            return None;
        }
        let age_ms = observed_at
            .signed_duration_since(self.diagnostic.preflight_checked_at)
            .num_milliseconds();
        (age_ms >= 0).then_some(age_ms)
    }
}

#[derive(Debug, Clone, PartialEq, Eq, thiserror::Error)]
pub enum FinamRealReadonlyTokenAccountPreflightApprovalError {
    #[error("FINAM real-readonly token/account preflight is blocked: {diagnostic:?}")]
    Blocked {
        diagnostic: Box<FinamRealReadonlyTokenAccountPreflightDiagnostic>,
    },
}

