#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
pub struct FinamRealReadonlyContractProbeSourceOrderDiagnostic {
    pub ordered_sources: Vec<CancelBrokerTruthSource>,
    pub ordered_sources_sha256: String,
}

impl FinamRealReadonlyContractProbeSourceOrderDiagnostic {
    fn from_sources(sources: &[CancelBrokerTruthSource]) -> Self {
        let bytes = serde_json::to_vec(sources)
            .expect("real-readonly source order material is serializable");
        Self {
            ordered_sources: sources.to_vec(),
            ordered_sources_sha256: sha256_hex(&bytes),
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum FinamRealReadonlyProbeRunClockSource {
    OperatorProvided,
    MissingFallbackToFetcherObserved,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FinamRealReadonlyContractProbeOperatorRunConfig {
    pub enabled: bool,
    pub probe_run_started_at: Option<DateTime<Utc>>,
    pub sources: Vec<CancelBrokerTruthSource>,
    pub max_requests: usize,
    pub request_timeout_ms: u64,
    pub min_request_interval_ms: u64,
    pub redacted_output_location: Option<FinamRealReadonlyRedactedOutputLocation>,
    pub audit_store_mode: FinamRealReadonlyAuditStoreMode,
    pub retry_disabled: bool,
    pub background_loop_disabled: bool,
    pub scheduler_disabled: bool,
    pub operator_disable_procedure_documented: bool,
    pub preserve_transport_error_taxonomy: bool,
    pub token_account_preflight: Option<FinamRealReadonlyTokenAccountPreflightApproved>,
}

impl Default for FinamRealReadonlyContractProbeOperatorRunConfig {
    fn default() -> Self {
        Self {
            enabled: false,
            probe_run_started_at: None,
            sources: all_cancel_truth_sources().to_vec(),
            max_requests: FINAM_REAL_READONLY_CONTRACT_PROBE_MAX_REQUESTS,
            request_timeout_ms: 10_000,
            min_request_interval_ms: 250,
            redacted_output_location: None,
            audit_store_mode: FinamRealReadonlyAuditStoreMode::EphemeralEvidenceStore,
            retry_disabled: true,
            background_loop_disabled: true,
            scheduler_disabled: true,
            operator_disable_procedure_documented: false,
            preserve_transport_error_taxonomy: true,
            token_account_preflight: None,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum FinamRealReadonlyContractProbeOperatorRunBlock {
    DisabledByDefault,
    RequestAccountMismatch,
    NoSources,
    MaxRequestsZero,
    MaxRequestsTooHigh,
    SourceCountExceedsMaxRequests,
    ProbeRunClockMissing,
    TimeoutMismatch,
    MinIntervalMismatch,
    OutputLocationMissing,
    RetryNotDisabled,
    BackgroundLoopNotDisabled,
    SchedulerNotDisabled,
    DisableProcedureMissing,
    TransportTaxonomyNotPreserved,
    TokenAccountPreflightMissing,
    TokenAccountPreflightFailed,
    TokenAccountPreflightRequestMismatch,
    TokenAccountPreflightExpired,
    PersistentAuditModeNotAllowed,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
pub struct FinamRealReadonlyContractProbeOperatorRunReport {
    pub enabled: bool,
    pub blocking_reasons: Vec<FinamRealReadonlyContractProbeOperatorRunBlock>,
    pub probe_run_started_at: DateTime<Utc>,
    pub probe_run_clock_source: FinamRealReadonlyProbeRunClockSource,
    pub probe_run_id: String,
    pub probe_run_fingerprint: String,
    pub approval_diagnostic: RealReadonlyBrokerTruthRunApprovalDiagnostic,
    pub output_location: Option<FinamRealReadonlyRedactedOutputLocation>,
    pub audit_store_mode: FinamRealReadonlyAuditStoreMode,
    pub retry_disabled: bool,
    pub background_loop_disabled: bool,
    pub scheduler_disabled: bool,
    pub operator_disable_procedure_documented: bool,
    pub preserve_transport_error_taxonomy: bool,
    pub token_account_preflight: Option<FinamRealReadonlyTokenAccountPreflightDiagnostic>,
    pub computed_preflight_age_ms: Option<i64>,
    pub request_snapshot: CancelBrokerTruthFetchRequestRedactedDiagnostic,
    pub source_order: FinamRealReadonlyContractProbeSourceOrderDiagnostic,
    pub attempt_count: usize,
    pub captured_response_count: usize,
    pub actual_http_send_started_count: usize,
    pub actual_http_send_completed_count: usize,
    pub requested_sources_count: usize,
    pub actual_send_count: usize,
    pub max_requests: usize,
    pub probe_report: Option<FinamRealReadonlyContractProbeReport>,
    pub evidence_matrix: Vec<FinamRealReadonlyContractProbeEvidenceMatrixRow>,
    pub transport_error_actions: Vec<FinamRealReadonlyTransportErrorOperatorActionDiagnostic>,
}

fn build_finam_real_readonly_probe_run_identity(
    started_at: DateTime<Utc>,
    approval: &RealReadonlyBrokerTruthRunApprovalDiagnostic,
    request: &CancelBrokerTruthFetchRequestRedactedDiagnostic,
    source_order: &FinamRealReadonlyContractProbeSourceOrderDiagnostic,
    sources: &[CancelBrokerTruthSource],
    max_requests: usize,
) -> (String, String) {
    let seed = format!(
        "{}:{}:{}:{}:{}:{}:{:?}:{}",
        started_at.to_rfc3339_opts(SecondsFormat::Millis, true),
        approval.account_id_sha256,
        approval.rest_base_url_sha256,
        approval.request_timeout_ms,
        request.request_snapshot_fingerprint,
        source_order.ordered_sources_sha256,
        sources,
        max_requests
    );
    let fingerprint = sha256_hex(seed.as_bytes());
    let probe_run_id = fingerprint.chars().take(16).collect::<String>();
    (probe_run_id, fingerprint)
}

async fn run_finam_real_readonly_contract_probe<T>(
    fetcher: &mut FinamRealReadonlyBrokerTruthAsyncFetcher<T>,
    request: CancelBrokerTruthFetchRequestSnapshot,
    config: &FinamRealReadonlyContractProbeConfig,
    probe_run_fingerprint: String,
) -> FinamRealReadonlyContractProbeReport
where
    T: FinamRealReadonlyBrokerTruthTransport,
{
    if !config.enabled {
        return FinamRealReadonlyContractProbeReport {
            enabled: false,
            blocking_reasons: vec![FinamRealReadonlyContractProbeBlock::DisabledByDefault],
            attempted_sources: Vec::new(),
            source_diagnostics: Vec::new(),
            attempt_records: Vec::new(),
            route_diagnostics: Vec::new(),
            captured_diagnostics: Vec::new(),
            reconciliation_summaries: Vec::new(),
            audit_records: Vec::new(),
        };
    }

    if config.max_requests == 0 {
        return FinamRealReadonlyContractProbeReport {
            enabled: true,
            blocking_reasons: vec![FinamRealReadonlyContractProbeBlock::MaxRequestsZero],
            attempted_sources: Vec::new(),
            source_diagnostics: Vec::new(),
            attempt_records: Vec::new(),
            route_diagnostics: Vec::new(),
            captured_diagnostics: Vec::new(),
            reconciliation_summaries: Vec::new(),
            audit_records: Vec::new(),
        };
    }
    if config.max_requests > FINAM_REAL_READONLY_CONTRACT_PROBE_MAX_REQUESTS {
        return FinamRealReadonlyContractProbeReport {
            enabled: true,
            blocking_reasons: vec![FinamRealReadonlyContractProbeBlock::MaxRequestsTooHigh],
            attempted_sources: Vec::new(),
            source_diagnostics: Vec::new(),
            attempt_records: Vec::new(),
            route_diagnostics: Vec::new(),
            captured_diagnostics: Vec::new(),
            reconciliation_summaries: Vec::new(),
            audit_records: Vec::new(),
        };
    }

    let mut sources = config
        .sources
        .iter()
        .copied()
        .filter(|source| all_cancel_truth_sources().contains(source))
        .collect::<Vec<_>>();
    sources.dedup();
    if sources.is_empty() {
        return FinamRealReadonlyContractProbeReport {
            enabled: true,
            blocking_reasons: vec![FinamRealReadonlyContractProbeBlock::NoSources],
            attempted_sources: Vec::new(),
            source_diagnostics: Vec::new(),
            attempt_records: Vec::new(),
            route_diagnostics: Vec::new(),
            captured_diagnostics: Vec::new(),
            reconciliation_summaries: Vec::new(),
            audit_records: Vec::new(),
        };
    }
    if sources.len() > config.max_requests {
        return FinamRealReadonlyContractProbeReport {
            enabled: true,
            blocking_reasons: vec![
                FinamRealReadonlyContractProbeBlock::SourceCountExceedsMaxRequests,
            ],
            attempted_sources: Vec::new(),
            source_diagnostics: Vec::new(),
            attempt_records: Vec::new(),
            route_diagnostics: Vec::new(),
            captured_diagnostics: Vec::new(),
            reconciliation_summaries: Vec::new(),
            audit_records: Vec::new(),
        };
    }

    let route_start = fetcher.route_diagnostics().len();
    let captured_start = fetcher.captured_diagnostics().len();
    let reconciliation_summary_start = fetcher.reconciliation_summaries().len();
    let audit_start = fetcher.audit_records().len();
    let mut source_diagnostics = Vec::new();
    let mut attempt_records = Vec::new();

    for (index, source) in sources.iter().copied().enumerate() {
        let attempt_id = (index + 1) as u32;
        let attempt_route_start = fetcher.route_diagnostics().len();
        let attempt_captured_start = fetcher.captured_diagnostics().len();
        let attempt_reconciliation_summary_start = fetcher.reconciliation_summaries().len();
        let attempt_audit_start = fetcher.audit_records().len();
        let attempt_started_at = Utc::now();
        let attempt_timer = Instant::now();
        let result = match source {
            CancelBrokerTruthSource::GetOrder => fetcher.fetch_get_order(request.clone()).await,
            CancelBrokerTruthSource::OrdersSnapshot => {
                fetcher.fetch_orders_snapshot(request.clone()).await
            }
            CancelBrokerTruthSource::TradesSnapshot => {
                fetcher.fetch_trades_snapshot(request.clone()).await
            }
            CancelBrokerTruthSource::PositionSnapshot => {
                fetcher.fetch_position_snapshot(request.clone()).await
            }
        };
        let attempt_completed_at = Utc::now();
        let attempt_elapsed_ms =
            u64::try_from(attempt_timer.elapsed().as_millis()).unwrap_or(u64::MAX);
        let reason = cancel_broker_truth_fetch_result_reason(&result);
        let source_diagnostic = FinamRealReadonlyContractProbeSourceDiagnostic {
            attempt_id,
            source,
            attempted: true,
            outcome: fetch_outcome_kind(reason),
            reason,
        };
        source_diagnostics.push(source_diagnostic.clone());
        attempt_records.push(FinamRealReadonlyContractProbeAttemptRecord {
            probe_run_fingerprint: probe_run_fingerprint.clone(),
            attempt_id,
            source,
            attempt_started_at,
            attempt_completed_at,
            attempt_elapsed_ms,
            source_diagnostic,
            route_diagnostic: fetcher
                .route_diagnostics()
                .get(attempt_route_start)
                .cloned(),
            captured_diagnostic: fetcher
                .captured_diagnostics()
                .get(attempt_captured_start)
                .cloned(),
            reconciliation_summary: fetcher
                .reconciliation_summaries()
                .get(attempt_reconciliation_summary_start)
                .cloned(),
            audit_record: fetcher.audit_records().get(attempt_audit_start).cloned(),
        });
    }

    FinamRealReadonlyContractProbeReport {
        enabled: true,
        blocking_reasons: Vec::new(),
        attempted_sources: sources.clone(),
        source_diagnostics,
        attempt_records,
        route_diagnostics: fetcher.route_diagnostics()[route_start..].to_vec(),
        captured_diagnostics: fetcher.captured_diagnostics()[captured_start..].to_vec(),
        reconciliation_summaries: fetcher.reconciliation_summaries()
            [reconciliation_summary_start..]
            .to_vec(),
        audit_records: fetcher.audit_records()[audit_start..].to_vec(),
    }
}

pub async fn run_finam_real_readonly_operator_contract_probe<T>(
    fetcher: &mut FinamRealReadonlyBrokerTruthAsyncFetcher<T>,
    request: CancelBrokerTruthFetchRequestSnapshot,
    config: &FinamRealReadonlyContractProbeOperatorRunConfig,
) -> FinamRealReadonlyContractProbeOperatorRunReport
where
    T: FinamRealReadonlyBrokerTruthTransport,
{
    let approval_diagnostic = fetcher.run_approval.diagnostic();
    let mut blocking_reasons = Vec::new();

    if !config.enabled {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::DisabledByDefault);
    }
    if !fetcher.run_approval.allows_request(&request) {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::RequestAccountMismatch);
    }
    if config.sources.is_empty() {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::NoSources);
    }
    if config.max_requests == 0 {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::MaxRequestsZero);
    }
    if config.max_requests > FINAM_REAL_READONLY_CONTRACT_PROBE_MAX_REQUESTS {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::MaxRequestsTooHigh);
    }
    let mut deduped_sources = config
        .sources
        .iter()
        .copied()
        .filter(|source| all_cancel_truth_sources().contains(source))
        .collect::<Vec<_>>();
    deduped_sources.dedup();
    let request_diagnostic =
        CancelBrokerTruthFetchRequestRedactedDiagnostic::from_snapshot(&request);
    let source_order =
        FinamRealReadonlyContractProbeSourceOrderDiagnostic::from_sources(&deduped_sources);
    let (probe_run_started_at, probe_run_clock_source) = match config.probe_run_started_at {
        Some(started_at) => (
            started_at,
            FinamRealReadonlyProbeRunClockSource::OperatorProvided,
        ),
        None => (
            fetcher.observed_ts,
            FinamRealReadonlyProbeRunClockSource::MissingFallbackToFetcherObserved,
        ),
    };
    let (probe_run_id, probe_run_fingerprint) = build_finam_real_readonly_probe_run_identity(
        probe_run_started_at,
        &approval_diagnostic,
        &request_diagnostic,
        &source_order,
        &deduped_sources,
        config.max_requests,
    );
    if config.enabled && config.probe_run_started_at.is_none() {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::ProbeRunClockMissing);
    }
    if deduped_sources.len() > config.max_requests {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::SourceCountExceedsMaxRequests);
    }
    if config.request_timeout_ms != approval_diagnostic.request_timeout_ms {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::TimeoutMismatch);
    }
    if config.min_request_interval_ms != approval_diagnostic.min_request_interval_ms {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::MinIntervalMismatch);
    }
    if config.redacted_output_location.is_none() {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::OutputLocationMissing);
    }
    if !config.retry_disabled {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::RetryNotDisabled);
    }
    if !config.background_loop_disabled {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::BackgroundLoopNotDisabled);
    }
    if !config.scheduler_disabled {
        blocking_reasons.push(FinamRealReadonlyContractProbeOperatorRunBlock::SchedulerNotDisabled);
    }
    if !config.operator_disable_procedure_documented {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::DisableProcedureMissing);
    }
    if !config.preserve_transport_error_taxonomy {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::TransportTaxonomyNotPreserved);
    }
    match &config.token_account_preflight {
        Some(preflight) => {
            if !preflight.allows_request(&request) {
                blocking_reasons.push(
                    FinamRealReadonlyContractProbeOperatorRunBlock::TokenAccountPreflightRequestMismatch,
                );
            }
            if !preflight.is_fresh_at(probe_run_started_at) {
                blocking_reasons.push(
                    FinamRealReadonlyContractProbeOperatorRunBlock::TokenAccountPreflightExpired,
                );
            }
        }
        None => {
            blocking_reasons
                .push(FinamRealReadonlyContractProbeOperatorRunBlock::TokenAccountPreflightMissing);
        }
    }
    let computed_preflight_age_ms = config
        .token_account_preflight
        .as_ref()
        .and_then(|preflight| preflight.computed_age_ms_at(probe_run_started_at));
    if config.audit_store_mode != FinamRealReadonlyAuditStoreMode::EphemeralEvidenceStore {
        blocking_reasons
            .push(FinamRealReadonlyContractProbeOperatorRunBlock::PersistentAuditModeNotAllowed);
    }

    if !blocking_reasons.is_empty() {
        return FinamRealReadonlyContractProbeOperatorRunReport {
            enabled: config.enabled,
            blocking_reasons,
            probe_run_started_at,
            probe_run_clock_source,
            probe_run_id: probe_run_id.clone(),
            probe_run_fingerprint: probe_run_fingerprint.clone(),
            approval_diagnostic,
            output_location: config.redacted_output_location.clone(),
            audit_store_mode: config.audit_store_mode,
            retry_disabled: config.retry_disabled,
            background_loop_disabled: config.background_loop_disabled,
            scheduler_disabled: config.scheduler_disabled,
            operator_disable_procedure_documented: config.operator_disable_procedure_documented,
            preserve_transport_error_taxonomy: config.preserve_transport_error_taxonomy,
            token_account_preflight: config
                .token_account_preflight
                .as_ref()
                .map(|approval| approval.diagnostic().clone()),
            computed_preflight_age_ms,
            request_snapshot: request_diagnostic,
            source_order,
            attempt_count: 0,
            captured_response_count: 0,
            actual_http_send_started_count: 0,
            actual_http_send_completed_count: 0,
            requested_sources_count: deduped_sources.len(),
            actual_send_count: 0,
            max_requests: config.max_requests,
            probe_report: None,
            evidence_matrix: Vec::new(),
            transport_error_actions: Vec::new(),
        };
    }

    let probe_report = run_finam_real_readonly_contract_probe(
        fetcher,
        request,
        &FinamRealReadonlyContractProbeConfig {
            enabled: true,
            sources: deduped_sources,
            max_requests: config.max_requests,
        },
        probe_run_fingerprint.clone(),
    )
    .await;
    let transport_error_actions = probe_report
        .audit_records
        .iter()
        .filter_map(|record| {
            record.transport_error_category.map(|category| {
                FinamRealReadonlyTransportErrorOperatorActionDiagnostic {
                    source: record.source,
                    http_status: record.http_status,
                    category,
                    operator_action: finam_real_readonly_transport_error_operator_action(category),
                }
            })
        })
        .collect::<Vec<_>>();
    let evidence_matrix = build_finam_real_readonly_contract_probe_evidence_matrix(
        &probe_report,
        config.min_request_interval_ms,
    );
    let attempt_count = probe_report.attempt_records.len();
    let captured_response_count = probe_report
        .attempt_records
        .iter()
        .filter(|record| record.captured_diagnostic.is_some())
        .count();
    let actual_http_send_started_count = probe_report
        .attempt_records
        .iter()
        .filter(|record| {
            record
                .captured_diagnostic
                .as_ref()
                .is_some_and(|diagnostic| diagnostic.actual_http_send_started)
        })
        .count();
    let actual_http_send_completed_count = probe_report
        .attempt_records
        .iter()
        .filter(|record| {
            record
                .captured_diagnostic
                .as_ref()
                .is_some_and(|diagnostic| diagnostic.actual_http_send_completed)
        })
        .count();

    FinamRealReadonlyContractProbeOperatorRunReport {
        enabled: true,
        blocking_reasons: Vec::new(),
        probe_run_started_at,
        probe_run_clock_source,
        probe_run_id,
        probe_run_fingerprint,
        approval_diagnostic,
        output_location: config.redacted_output_location.clone(),
        audit_store_mode: config.audit_store_mode,
        retry_disabled: config.retry_disabled,
        background_loop_disabled: config.background_loop_disabled,
        scheduler_disabled: config.scheduler_disabled,
        operator_disable_procedure_documented: config.operator_disable_procedure_documented,
        preserve_transport_error_taxonomy: config.preserve_transport_error_taxonomy,
        token_account_preflight: config
            .token_account_preflight
            .as_ref()
            .map(|approval| approval.diagnostic().clone()),
        computed_preflight_age_ms,
        request_snapshot: request_diagnostic,
        source_order,
        attempt_count,
        captured_response_count,
        actual_http_send_started_count,
        actual_http_send_completed_count,
        requested_sources_count: probe_report.attempted_sources.len(),
        actual_send_count: actual_http_send_started_count,
        max_requests: config.max_requests,
        probe_report: Some(probe_report),
        evidence_matrix,
        transport_error_actions,
    }
}

fn build_finam_real_readonly_contract_probe_evidence_matrix(
    report: &FinamRealReadonlyContractProbeReport,
    min_request_interval_ms: u64,
) -> Vec<FinamRealReadonlyContractProbeEvidenceMatrixRow> {
    let mut previous_http_send_started_at = None;
    report
        .attempt_records
        .iter()
        .map(|attempt| {
            let route = attempt.route_diagnostic.as_ref();
            let captured = attempt.captured_diagnostic.as_ref();
            let reconciliation_summary = attempt.reconciliation_summary.as_ref();
            let audit = attempt.audit_record.as_ref();
            let transport_error_category = captured
                .and_then(|diagnostic| diagnostic.transport_error_category)
                .or_else(|| audit.and_then(|record| record.transport_error_category));
            let audit_record_sha256 = audit.and_then(|record| {
                serde_json::to_vec(record)
                    .ok()
                    .map(|encoded| sha256_hex(&encoded))
            });
            let actual_http_send_started_at =
                captured.and_then(|diagnostic| diagnostic.actual_http_send_started_at);
            let inter_attempt_gap_ms = actual_http_send_started_at.and_then(|started_at| {
                previous_http_send_started_at.map(|previous| {
                    started_at
                        .signed_duration_since(previous)
                        .num_milliseconds()
                })
            });
            previous_http_send_started_at = actual_http_send_started_at;
            FinamRealReadonlyContractProbeEvidenceMatrixRow {
                probe_run_fingerprint: attempt.probe_run_fingerprint.clone(),
                attempt_id: attempt.attempt_id,
                source: attempt.source,
                attempt_started_at: attempt.attempt_started_at,
                attempt_completed_at: attempt.attempt_completed_at,
                attempt_elapsed_ms: attempt.attempt_elapsed_ms,
                inter_attempt_gap_ms,
                min_request_interval_ms,
                actual_http_send_started: captured
                    .is_some_and(|diagnostic| diagnostic.actual_http_send_started),
                actual_http_send_completed: captured
                    .is_some_and(|diagnostic| diagnostic.actual_http_send_completed),
                actual_http_send_started_at,
                actual_http_send_completed_at: captured
                    .and_then(|diagnostic| diagnostic.actual_http_send_completed_at),
                actual_http_send_elapsed_ms: captured
                    .and_then(|diagnostic| diagnostic.actual_http_send_elapsed_ms),
                route_template: route.map(|diagnostic| diagnostic.path_template.to_string()),
                http_status: captured
                    .map(|diagnostic| diagnostic.status)
                    .or_else(|| audit.and_then(|record| record.http_status)),
                http_body_present: captured.map(|diagnostic| diagnostic.body_present),
                http_body_len: captured.and_then(|diagnostic| diagnostic.body_len),
                http_body_sha256: captured.and_then(|diagnostic| diagnostic.body_sha256.clone()),
                mapped_fetch_reason: attempt.source_diagnostic.reason,
                outcome: attempt.source_diagnostic.outcome,
                transport_error_category,
                operator_action: transport_error_category
                    .map(finam_real_readonly_transport_error_operator_action),
                parsed_orders_count: reconciliation_summary
                    .and_then(|summary| summary.parsed_orders_count),
                matched_orders_count: reconciliation_summary
                    .and_then(|summary| summary.matched_orders_count),
                parsed_trades_count: reconciliation_summary
                    .and_then(|summary| summary.parsed_trades_count),
                matched_trades_count: reconciliation_summary
                    .and_then(|summary| summary.matched_trades_count),
                position_items_count: reconciliation_summary
                    .and_then(|summary| summary.position_items_count),
                position_identity_match_count: reconciliation_summary
                    .and_then(|summary| summary.position_identity_match_count),
                snapshot_complete: reconciliation_summary
                    .and_then(|summary| summary.snapshot_complete),
                snapshot_incomplete_reason: reconciliation_summary
                    .and_then(|summary| summary.snapshot_incomplete_reason),
                audit_record_sha256,
            }
        })
        .collect()
}

#[derive(Clone)]
pub struct LocalMockCancelBrokerTruthReadonlyHttpClient {
    responses: Vec<(
        CancelBrokerTruthSource,
        CancelBrokerTruthReadonlyHttpResponse,
    )>,
    sent_specs: Vec<CancelBrokerTruthReadonlyRequestSpec>,
}

impl LocalMockCancelBrokerTruthReadonlyHttpClient {
    pub fn new(
        responses: impl IntoIterator<
            Item = (
                CancelBrokerTruthSource,
                CancelBrokerTruthReadonlyHttpResponse,
            ),
        >,
    ) -> Self {
        Self {
            responses: responses.into_iter().collect(),
            sent_specs: Vec::new(),
        }
    }

    pub fn sent_specs(&self) -> &[CancelBrokerTruthReadonlyRequestSpec] {
        &self.sent_specs
    }
}

#[async_trait]
impl CancelBrokerTruthReadonlyHttpClient for LocalMockCancelBrokerTruthReadonlyHttpClient {
    async fn send_readonly(
        &mut self,
        spec: CancelBrokerTruthReadonlyRequestSpec,
    ) -> CancelBrokerTruthReadonlyCapturedResponse {
        self.sent_specs.push(spec.clone());
        let response = self
            .responses
            .iter()
            .find(|(source, _)| *source == spec.source)
            .map(|(_, response)| response.clone())
            .unwrap_or_else(|| CancelBrokerTruthReadonlyHttpResponse::empty(404));
        CancelBrokerTruthReadonlyCapturedResponse::new(spec.source, response)
    }
}

pub struct HttpClientCancelBrokerTruthAsyncReadonlyFetcher<C> {
    client: C,
    freshness_policy: CancelBrokerTruthFreshnessPolicy,
    observed_ts: DateTime<Utc>,
    captured_diagnostics: Vec<CancelBrokerTruthReadonlyHttpDiagnostic>,
}

impl<C> HttpClientCancelBrokerTruthAsyncReadonlyFetcher<C>
where
    C: CancelBrokerTruthReadonlyHttpClient + Send,
{
    pub fn new(
        client: C,
        freshness_policy: CancelBrokerTruthFreshnessPolicy,
        observed_ts: DateTime<Utc>,
    ) -> Self {
        Self {
            client,
            freshness_policy,
            observed_ts,
            captured_diagnostics: Vec::new(),
        }
    }

    pub fn captured_diagnostics(&self) -> &[CancelBrokerTruthReadonlyHttpDiagnostic] {
        &self.captured_diagnostics
    }

    pub fn client(&self) -> &C {
        &self.client
    }

    async fn fetch_source(
        &mut self,
        source: CancelBrokerTruthSource,
        request: CancelBrokerTruthFetchRequestSnapshot,
    ) -> CancelBrokerTruthFetchResult {
        let spec = build_cancel_broker_truth_readonly_request_spec(source, &request);
        let captured = self.client.send_readonly(spec).await;
        self.captured_diagnostics
            .push(captured.diagnostic().clone());
        match captured.source() {
            CancelBrokerTruthSource::GetOrder => map_cancel_broker_truth_get_order_http_response(
                &captured.response,
                &request,
                self.observed_ts,
                &self.freshness_policy,
            ),
            CancelBrokerTruthSource::OrdersSnapshot => {
                map_cancel_broker_truth_orders_snapshot_http_response(
                    &captured.response,
                    &request,
                    self.observed_ts,
                    &self.freshness_policy,
                )
            }
            CancelBrokerTruthSource::TradesSnapshot => {
                map_cancel_broker_truth_trades_snapshot_http_response(
                    &captured.response,
                    &request,
                    self.observed_ts,
                    &self.freshness_policy,
                )
            }
            CancelBrokerTruthSource::PositionSnapshot => {
                map_cancel_broker_truth_position_snapshot_http_response(
                    &captured.response,
                    &request,
                    self.observed_ts,
                    &self.freshness_policy,
                )
            }
        }
    }
}

