    #[test]
    fn m3i3_local_shape_validation_rejects_impossible_paper_outputs() {
        let valid = M3iPaperStrategySignal {
            kind: M3iPaperStrategySignalKind::EnterLong,
            order_type: OrderType::Limit,
            qty: Decimal::ONE,
            limit_price: Some(Decimal::new(5000, 0)),
            time_in_force: TimeInForce::Day,
            suppress_reason: None,
        };
        assert_eq!(m3i3_validate_paper_strategy_signal(&valid), Ok(()));

        for (signal, reason) in [
            (
                M3iPaperStrategySignal {
                    order_type: OrderType::Market,
                    limit_price: Some(Decimal::new(5000, 0)),
                    ..valid.clone()
                },
                M3iPaperStrategyOutputRejectReason::MarketWithLimitPrice,
            ),
            (
                M3iPaperStrategySignal {
                    order_type: OrderType::Limit,
                    limit_price: None,
                    ..valid.clone()
                },
                M3iPaperStrategyOutputRejectReason::LimitWithoutLimitPrice,
            ),
            (
                M3iPaperStrategySignal {
                    qty: Decimal::ZERO,
                    ..valid.clone()
                },
                M3iPaperStrategyOutputRejectReason::NonPositiveQty,
            ),
            (
                M3iPaperStrategySignal {
                    order_type: OrderType::Stop,
                    ..valid.clone()
                },
                M3iPaperStrategyOutputRejectReason::StopSltpBracketReplaceMultilegForbidden,
            ),
            (
                M3iPaperStrategySignal {
                    time_in_force: TimeInForce::ImmediateOrCancel,
                    ..valid.clone()
                },
                M3iPaperStrategyOutputRejectReason::UnsupportedTimeInForce,
            ),
        ] {
            assert_eq!(m3i3_validate_paper_strategy_signal(&signal), Err(reason));
            assert!(matches!(
                m3i3_build_paper_strategy_output(
                    &sample_m3i_strategy_input(),
                    signal,
                    M3iPaperStrategyIdentityContext::new(
                        BrokerAccountId::new("ACC_TEST_0001"),
                        "strategy-v1",
                        "params:a",
                    ),
                    Utc.with_ymd_and_hms(2026, 7, 4, 10, 4, 0)
                        .single()
                        .expect("timestamp"),
                ),
                M3iPaperStrategyOutputOutcome::Suppressed { .. }
            ));
        }
    }

    #[test]
    fn m3i3_json_state_restore_keeps_pending_published_and_dropped_terminal() {
        let path = temp_m3i3_state_path("restore");
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 5, 0)
            .single()
            .expect("timestamp");
        let input = sample_m3i_strategy_input();
        let M3iPaperStrategyOutputOutcome::Candidate(pending_candidate) =
            m3i3_build_paper_strategy_output(
                &input,
                M3iPaperStrategySignal {
                    kind: M3iPaperStrategySignalKind::EnterLong,
                    order_type: OrderType::Market,
                    qty: Decimal::ONE,
                    limit_price: None,
                    time_in_force: TimeInForce::Day,
                    suppress_reason: None,
                },
                M3iPaperStrategyIdentityContext::new(
                    BrokerAccountId::new("ACC_TEST_0001"),
                    "strategy-v1",
                    "params:a",
                ),
                now,
            )
        else {
            panic!("expected pending candidate");
        };
        let store = M3iJsonPaperStrategyStateStore::open(&path).expect("open m3i state");
        let mut state = store.load().expect("load initial state");
        assert_eq!(
            m3i2_stage_pending_before_m3h_emission(&mut state, &pending_candidate).action,
            M3iPaperStrategyStateAction::PendingStaged
        );
        store.save(state).expect("save pending");

        let restored = M3iJsonPaperStrategyStateStore::open(&path).expect("reopen pending");
        let mut restored_state = restored.load().expect("load pending");
        assert_eq!(
            m3i2_stage_pending_before_m3h_emission(&mut restored_state, &pending_candidate).action,
            M3iPaperStrategyStateAction::DuplicateIgnored
        );

        let published = M3hRuntimeDryCommandEmitOutcome::CommandPublished {
            request_id: pending_candidate.request_id,
            command_kind: M3eCommandKind::PlaceOrder,
            stream: "finam:commands".to_string(),
            state: M3hRuntimeDryCommandLifecycleState::PublishedToM3eCommandStream,
        };
        assert_eq!(
            m3i2_apply_m3h_emit_outcome_to_strategy_state(
                &mut restored_state,
                pending_candidate.request_id,
                &published,
            )
            .action,
            M3iPaperStrategyStateAction::PublishedPendingDryAck
        );
        restored.save(restored_state).expect("save published");
        let after_published =
            M3iJsonPaperStrategyStateStore::open(&path).expect("reopen published");
        let mut after_published_state = after_published.load().expect("load published");
        assert_eq!(
            m3i2_stage_pending_before_m3h_emission(&mut after_published_state, &pending_candidate,)
                .action,
            M3iPaperStrategyStateAction::DuplicateIgnored
        );

        let M3iPaperStrategyOutputOutcome::Candidate(dropped_candidate) =
            m3i3_build_paper_strategy_output(
                &input,
                M3iPaperStrategySignal {
                    kind: M3iPaperStrategySignalKind::EnterShort,
                    order_type: OrderType::Market,
                    qty: Decimal::ONE,
                    limit_price: None,
                    time_in_force: TimeInForce::Day,
                    suppress_reason: None,
                },
                M3iPaperStrategyIdentityContext::new(
                    BrokerAccountId::new("ACC_TEST_0001"),
                    "strategy-v1",
                    "params:a",
                ),
                now,
            )
        else {
            panic!("expected dropped candidate");
        };
        m3i2_stage_pending_before_m3h_emission(&mut after_published_state, &dropped_candidate);
        assert_eq!(
            m3i2_apply_m3h_emit_outcome_to_strategy_state(
                &mut after_published_state,
                dropped_candidate.request_id,
                &M3hRuntimeDryCommandEmitOutcome::NotEmitted {
                    request_id: Some(dropped_candidate.request_id),
                    reason: M3hRuntimeDryCommandNonEmissionReason::ReadinessNotDryReady,
                    pending_state_preserved: false,
                },
            )
            .action,
            M3iPaperStrategyStateAction::PendingDroppedAfterNotEmitted
        );
        after_published
            .save(after_published_state)
            .expect("save dropped");
        let terminal = M3iJsonPaperStrategyStateStore::open(&path)
            .expect("reopen terminal")
            .load()
            .expect("load terminal");
        assert!(terminal
            .pending_request_ids
            .contains(&pending_candidate.request_id));
        assert!(!terminal
            .pending_request_ids
            .contains(&dropped_candidate.request_id));
        assert_eq!(terminal.dropped_request_hashes.len(), 1);
        let report = m3i2_paper_strategy_replay_report(&terminal, 2, 2, 1, 0, now);
        assert_eq!(report.pending_request_hashes.len(), 1);
        assert_eq!(report.dropped_intent_count, 1);
        assert!(!report.raw_request_ids_exported);
    }

    #[tokio::test]
    async fn m3i4_e2e_live_final_to_strategy_output_m3h_m3e_dry_ack_updates_state() {
        let gateway_config = GatewayConfig::default();
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 10, 0)
            .single()
            .expect("timestamp");
        let mut runtime_consumer = M3hRuntimeShadowConsumer::from_gateway_config(&gateway_config);
        let mut bar = sample_bar(MarketDataSourceKind::LiveStream, true);
        bar.open_ts = now;
        bar.close_ts = now + ChronoDuration::minutes(1);
        let shadow_entry = m3h1_runtime_entry(
            &gateway_config.redis.market_data_stream,
            "m3i4-1",
            MessageType::MarketData,
            MarketDataEvent::Bar(bar.clone()),
        );
        let M3hRuntimeShadowAdapterOutcome::Accepted(shadow_input) =
            m3h1_adapt_runtime_shadow_entry(&gateway_config.redis, &shadow_entry)
        else {
            panic!("expected m3h shadow input");
        };
        let decision = runtime_consumer.consume_entry(shadow_entry);
        let M3iStrategyPaperInputAdapterOutcome::Accepted(strategy_input) =
            m3i1_adapt_strategy_paper_input("paper-simple", &shadow_input, &decision)
        else {
            panic!("expected m3i strategy input");
        };
        let M3iPaperStrategyOutputOutcome::Candidate(candidate) = m3i3_build_paper_strategy_output(
            &strategy_input,
            M3iPaperStrategySignal {
                kind: M3iPaperStrategySignalKind::EnterLong,
                order_type: OrderType::Market,
                qty: Decimal::ONE,
                limit_price: None,
                time_in_force: TimeInForce::Day,
                suppress_reason: None,
            },
            M3iPaperStrategyIdentityContext::new(
                BrokerAccountId::new("ACC_TEST_0001"),
                "strategy-v1",
                "params:a",
            ),
            now,
        ) else {
            panic!("expected paper output candidate");
        };
        let mut state = M3iPaperStrategyState::default();
        assert_eq!(
            m3i2_stage_pending_before_m3h_emission(&mut state, &candidate).action,
            M3iPaperStrategyStateAction::PendingStaged
        );
        let command_sink = InMemoryRedisStreamSink::default();
        let mut emitter =
            M3hRuntimeDryCommandEmitter::from_gateway_config(&gateway_config, command_sink.clone());
        let dry_candidate =
            m3i2_to_m3h_dry_command_candidate(&candidate).expect("to m3h dry candidate");
        let published = emitter
            .emit_candidate(&decision, &m3h_dry_ready_decision(), dry_candidate, now)
            .await
            .expect("m3h dry emit");
        assert!(matches!(
            m3i2_apply_m3h_emit_outcome_to_strategy_state(
                &mut state,
                candidate.request_id,
                &published,
            )
            .action,
            M3iPaperStrategyStateAction::PublishedPendingDryAck
        ));

        let command_entries = command_sink.entries().expect("command entries");
        assert_eq!(command_entries.len(), 1);
        let m3e_entry = runtime_entries(command_entries)
            .into_iter()
            .next()
            .expect("m3e command entry");
        let m3e_consumer = M3eCommandConsumerDurableDryRun::new(
            M3eCommandConsumerConfig::from_gateway_config(&gateway_config),
            InMemoryRedisStreamSink::default(),
            M3eInMemoryCommandLifecycleStore::default(),
        );
        let m3e_report = m3e_consumer
            .process_entry(m3e_entry, now)
            .await
            .expect("m3e dry ack");
        let (transition, ack_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            candidate.request_id,
            Some(&m3e_report),
        );
        assert_eq!(
            ack_kind,
            M3iPaperStrategyAckApplyOutcomeKind::DryRunAcknowledged
        );
        assert_eq!(
            transition.action,
            M3iPaperStrategyStateAction::DryAckApplied
        );
        assert!(state.pending_request_ids.is_empty());
        assert_eq!(state.acknowledged_request_hashes.len(), 1);

        let report = m3i4_paper_shadow_replay_ack_report(&state, now, 1, 1, 1, 1, &[ack_kind]);
        assert_eq!(report.live_final_bar_fixture_count, 1);
        assert_eq!(report.m3e_dry_ack_count, 1);
        assert_eq!(report.final_acknowledged_count, 1);
        assert!(report.only_m3h_output_path);
        assert!(!report.direct_strategy_publish_allowed);
        assert!(!report.runtime_live_attachment_allowed);
        assert!(!report.live_ready_allowed);
        assert!(!report.external_order_endpoint_allowed);
        assert!(!report.real_finam_order_endpoint_used);
        assert!(report.tif_policy_scope.contains("TimeInForce::Day only"));
    }

    #[test]
    fn m3i4_ack_outcome_matrix_updates_paper_state_without_live_boundary() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 11, 0)
            .single()
            .expect("timestamp");
        let mut state = M3iPaperStrategyState::default();
        let dry_id = request_id(700);
        state.pending_request_ids.insert(dry_id);
        let (_, dry_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            dry_id,
            Some(&sample_m3e_ack_report(
                dry_id,
                CommandAckStatus::Rejected,
                Some(CommandAckReasonCode::DryRunOnly),
                now,
            )),
        );
        assert_eq!(
            dry_kind,
            M3iPaperStrategyAckApplyOutcomeKind::DryRunAcknowledged
        );
        assert!(!state.pending_request_ids.contains(&dry_id));

        let duplicate_id = request_id(701);
        state.pending_request_ids.insert(duplicate_id);
        let (_, duplicate_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            duplicate_id,
            Some(&sample_m3e_ack_report(
                duplicate_id,
                CommandAckStatus::Duplicate,
                Some(CommandAckReasonCode::DuplicateCommand),
                now,
            )),
        );
        assert_eq!(
            duplicate_kind,
            M3iPaperStrategyAckApplyOutcomeKind::DuplicateAcknowledged
        );
        assert!(!state.pending_request_ids.contains(&duplicate_id));

        let expired_id = request_id(702);
        state.pending_request_ids.insert(expired_id);
        let (_, expired_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            expired_id,
            Some(&sample_m3e_ack_report(
                expired_id,
                CommandAckStatus::Expired,
                Some(CommandAckReasonCode::ExpiredCommand),
                now,
            )),
        );
        assert_eq!(
            expired_kind,
            M3iPaperStrategyAckApplyOutcomeKind::ExpiredDropped
        );
        assert!(!state.pending_request_ids.contains(&expired_id));

        let rejected_id = request_id(703);
        state.pending_request_ids.insert(rejected_id);
        let (_, rejected_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            rejected_id,
            Some(&sample_m3e_ack_report(
                rejected_id,
                CommandAckStatus::Rejected,
                Some(CommandAckReasonCode::LocalValidationRejected),
                now,
            )),
        );
        assert_eq!(
            rejected_kind,
            M3iPaperStrategyAckApplyOutcomeKind::RejectedDropped
        );
        assert!(!state.pending_request_ids.contains(&rejected_id));

        let missing_id = request_id(704);
        state.pending_request_ids.insert(missing_id);
        let (_, missing_kind) = m3i4_apply_m3e_ack_to_strategy_state(&mut state, missing_id, None);
        assert_eq!(
            missing_kind,
            M3iPaperStrategyAckApplyOutcomeKind::MissingOrStaleAck
        );
        assert!(state.pending_request_ids.contains(&missing_id));

        let manual_id = request_id(705);
        state.pending_request_ids.insert(manual_id);
        let (_, manual_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            manual_id,
            Some(&sample_m3e_ack_report(
                manual_id,
                CommandAckStatus::UnknownPending,
                Some(CommandAckReasonCode::TimeoutUnknownPending),
                now,
            )),
        );
        assert_eq!(
            manual_kind,
            M3iPaperStrategyAckApplyOutcomeKind::ManualPolicyRequired
        );
        assert!(state.pending_request_ids.contains(&manual_id));

        let report = m3i4_paper_shadow_replay_ack_report(
            &state,
            now,
            1,
            6,
            6,
            4,
            &[
                dry_kind,
                duplicate_kind,
                expired_kind,
                rejected_kind,
                missing_kind,
                manual_kind,
            ],
        );
        assert_eq!(report.m3e_dry_ack_count, 1);
        assert_eq!(report.duplicate_ack_count, 1);
        assert_eq!(report.expired_ack_count, 1);
        assert_eq!(report.rejected_ack_count, 1);
        assert_eq!(report.missing_or_stale_ack_count, 1);
        assert_eq!(report.final_manual_policy_count, 1);
        assert_eq!(report.final_pending_count, 2);
        assert!(!report.raw_request_ids_exported);
    }

    #[test]
    fn m3i4a_ack_application_requires_pending_and_replay_is_idempotent() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 12, 0)
            .single()
            .expect("timestamp");
        let mut state = M3iPaperStrategyState::default();
        let ack_request_id = request_id(710);
        state.pending_request_ids.insert(ack_request_id);
        let dry_ack = sample_m3e_ack_report(
            ack_request_id,
            CommandAckStatus::Rejected,
            Some(CommandAckReasonCode::DryRunOnly),
            now,
        );
        let (first_transition, first_kind) =
            m3i4_apply_m3e_ack_to_strategy_state(&mut state, ack_request_id, Some(&dry_ack));
        assert_eq!(
            first_transition.action,
            M3iPaperStrategyStateAction::DryAckApplied
        );
        assert_eq!(
            first_kind,
            M3iPaperStrategyAckApplyOutcomeKind::DryRunAcknowledged
        );
        assert_eq!(state.acknowledged_request_hashes.len(), 1);
        assert!(state.pending_request_ids.is_empty());

        let before_replay = state.clone();
        let (replay_transition, replay_kind) =
            m3i4_apply_m3e_ack_to_strategy_state(&mut state, ack_request_id, Some(&dry_ack));
        assert_eq!(
            replay_transition.action,
            M3iPaperStrategyStateAction::AlreadyResolvedAck
        );
        assert_eq!(
            replay_kind,
            M3iPaperStrategyAckApplyOutcomeKind::AlreadyResolved
        );
        assert_eq!(state, before_replay);

        let unknown_id = request_id(711);
        let unknown_ack = sample_m3e_ack_report(
            unknown_id,
            CommandAckStatus::Rejected,
            Some(CommandAckReasonCode::DryRunOnly),
            now,
        );
        let before_unknown = state.clone();
        let (unknown_transition, unknown_kind) =
            m3i4_apply_m3e_ack_to_strategy_state(&mut state, unknown_id, Some(&unknown_ack));
        assert_eq!(
            unknown_transition.action,
            M3iPaperStrategyStateAction::AckForUnknownRequest
        );
        assert_eq!(
            unknown_kind,
            M3iPaperStrategyAckApplyOutcomeKind::UnknownAckIgnored
        );
        assert_eq!(state, before_unknown);

        let report = m3i4_paper_shadow_replay_ack_report(
            &state,
            now,
            1,
            1,
            1,
            1,
            &[first_kind, replay_kind, unknown_kind],
        );
        assert_eq!(report.m3e_dry_ack_count, 1);
        assert_eq!(report.already_resolved_ack_count, 1);
        assert_eq!(report.ack_for_unknown_count, 1);
        assert_eq!(report.final_acknowledged_count, 1);
    }

    #[test]
    fn m3i4a_non_pending_duplicate_and_missing_ack_do_not_create_false_accounting() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 13, 0)
            .single()
            .expect("timestamp");
        let mut state = M3iPaperStrategyState::default();
        let stray_duplicate_id = request_id(712);
        let stray_duplicate = sample_m3e_ack_report(
            stray_duplicate_id,
            CommandAckStatus::Duplicate,
            Some(CommandAckReasonCode::DuplicateCommand),
            now,
        );
        let (stray_transition, stray_kind) = m3i4_apply_m3e_ack_to_strategy_state(
            &mut state,
            stray_duplicate_id,
            Some(&stray_duplicate),
        );
        assert_eq!(
            stray_transition.action,
            M3iPaperStrategyStateAction::AckForUnknownRequest
        );
        assert_eq!(
            stray_kind,
            M3iPaperStrategyAckApplyOutcomeKind::UnknownAckIgnored
        );
        assert!(state.duplicate_request_hashes.is_empty());

        let missing_non_pending_id = request_id(713);
        let (_, missing_non_pending_kind) =
            m3i4_apply_m3e_ack_to_strategy_state(&mut state, missing_non_pending_id, None);
        assert_eq!(
            missing_non_pending_kind,
            M3iPaperStrategyAckApplyOutcomeKind::UnknownAckIgnored
        );
        assert!(state.stale_or_missing_ack_request_hashes.is_empty());

        let pending_missing_id = request_id(714);
        state.pending_request_ids.insert(pending_missing_id);
        let (pending_missing_transition, pending_missing_kind) =
            m3i4_apply_m3e_ack_to_strategy_state(&mut state, pending_missing_id, None);
        assert_eq!(
            pending_missing_transition.action,
            M3iPaperStrategyStateAction::PendingAckMissingOrStale
        );
        assert_eq!(
            pending_missing_kind,
            M3iPaperStrategyAckApplyOutcomeKind::MissingOrStaleAck
        );
        assert!(state.pending_request_ids.contains(&pending_missing_id));
        assert_eq!(state.stale_or_missing_ack_request_hashes.len(), 1);
    }

    #[test]
    fn m3i5_stage_closure_package_combines_all_m3i_invariants() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 20, 0)
            .single()
            .expect("timestamp");
        let closure = m3i5_paper_shadow_closure_report(sample_m3i5_closure_input(now, false));
        assert!(closure.m3i_paper_shadow_stage_closed);
        assert!(closure.stage_closure_report);
        assert!(closure.paper_shadow_e2e_replay_ok);
        assert!(closure.strategy_input_contract_ok);
        assert!(closure.strategy_output_contract_ok);
        assert!(closure.strategy_state_restore_ok);
        assert!(closure.ack_application_matrix_ok);
        assert!(closure.ack_correlation_idempotency_ok);
        assert!(closure.request_id_fingerprint_hardened);
        assert!(closure.no_direct_strategy_publish);
        assert!(closure.only_m3h_output_path);
        assert!(closure.no_live_boundary);
        assert!(closure.no_stop_sltp_bracket);
        assert!(closure.diagnostics_only_report_cannot_close);
        assert!(closure.unknown_ack_no_state_mutation);
        assert!(closure.already_resolved_ack_no_double_count);
        assert!(closure.non_pending_duplicate_no_false_accounting);
        assert!(closure.strategy_cannot_reach_reqwest_or_finam_endpoint);
        assert!(!closure.live_ready_allowed);
        assert!(!closure.runtime_live_attachment_allowed);
        assert!(!closure.external_order_endpoint_allowed);
        assert!(!closure.real_finam_order_endpoint_used);
        assert!(!closure.direct_strategy_publish_allowed);
        assert!(!closure.raw_request_ids_exported);
    }

    #[test]
    fn m3i5_diagnostics_only_or_unsafe_boundaries_cannot_close_stage() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 4, 10, 21, 0)
            .single()
            .expect("timestamp");
        let diagnostics_only =
            m3i5_paper_shadow_closure_report(sample_m3i5_closure_input(now, true));
        assert!(!diagnostics_only.m3i_paper_shadow_stage_closed);
        assert!(!diagnostics_only.diagnostics_only_report_cannot_close);

        let mut missing_ack_hardening = sample_m3i5_closure_input(now, false);
        missing_ack_hardening.unknown_ack_no_state_mutation = false;
        let report = m3i5_paper_shadow_closure_report(missing_ack_hardening);
        assert!(!report.m3i_paper_shadow_stage_closed);
        assert!(!report.ack_correlation_idempotency_ok);

        let mut direct_publish = sample_m3i5_closure_input(now, false);
        direct_publish.ack_report.direct_strategy_publish_allowed = true;
        let report = m3i5_paper_shadow_closure_report(direct_publish);
        assert!(!report.m3i_paper_shadow_stage_closed);
        assert!(!report.no_direct_strategy_publish);

        let mut live_ready = sample_m3i5_closure_input(now, false);
        live_ready.input_contract_report.live_ready_allowed = true;
        let report = m3i5_paper_shadow_closure_report(live_ready);
        assert!(!report.m3i_paper_shadow_stage_closed);
        assert!(!report.no_live_boundary);
    }

    #[tokio::test]
    async fn dry_command_ack_publisher_refuses_order_enabled_modes() {
        fn enable_command_consumer(features: &mut GatewayFeatureSet) {
            features.command_consumer_enabled = true;
        }
        fn enable_order_placement(features: &mut GatewayFeatureSet) {
            features.order_placement_enabled = true;
        }
        fn enable_cancel(features: &mut GatewayFeatureSet) {
            features.cancel_enabled = true;
        }
        fn enable_stop_sltp_bracket(features: &mut GatewayFeatureSet) {
            features.stop_sltp_bracket_enabled = true;
        }

        for (configure, reason) in [
            (
                enable_command_consumer as fn(&mut GatewayFeatureSet),
                "command_consumer_enabled",
            ),
            (
                enable_order_placement as fn(&mut GatewayFeatureSet),
                "order_placement_enabled",
            ),
            (
                enable_cancel as fn(&mut GatewayFeatureSet),
                "cancel_enabled",
            ),
            (
                enable_stop_sltp_bracket as fn(&mut GatewayFeatureSet),
                "stop_sltp_bracket_enabled",
            ),
        ] {
            let mut config = GatewayConfig::default();
            configure(&mut config.features);
            let gateway = FinamGateway::new(config, InMemoryRedisStreamSink::default());
            let ack = CommandAck {
                request_id: request_id(4),
                client_order_id: None,
                broker_order_id: None,
                status: CommandAckStatus::Submitted,
                reason: Some(CommandAckReason::synthetic_submitted()),
                received_ts: Utc::now(),
            };

            assert!(matches!(
                gateway
                    .publish_dry_command_ack(ack)
                    .await
                    .expect_err("order mode must be refused"),
                GatewayError::DryCommandAckPublisherUnsafeMode {
                    reason: actual
                } if actual == reason
            ));
        }
    }

    #[test]
    fn real_order_endpoint_gate_remains_blocked_until_post_m3a11_review() {
        let gateway =
            FinamGateway::new(GatewayConfig::default(), InMemoryRedisStreamSink::default());

        let decision = gateway.real_order_endpoint_gate_decision();

        assert!(!decision.endpoint_calls_allowed);
        assert_eq!(
            decision.blocking_reasons,
            vec![
                RealOrderEndpointGateBlock::M3a11PreEndpointReviewRequired,
                RealOrderEndpointGateBlock::M3cImplementationReviewRequired,
            ]
        );
        assert_eq!(
            decision.runtime_ack_id_policy,
            RuntimeCommandAckIdPolicy::RedactedRuntimeAckOnly
        );
        assert!(matches!(
            EndpointGateApproved::try_from_decision(&decision)
                .expect_err("M3b-0 marker must not be constructible"),
            EndpointGateApprovalError::Blocked { decision } if decision
                .blocking_reasons
                .contains(&RealOrderEndpointGateBlock::M3a11PreEndpointReviewRequired)
        ));

        let features = GatewayFeatureSet {
            real_order_endpoint_enabled: true,
            command_consumer_enabled: true,
            order_placement_enabled: true,
            cancel_enabled: true,
            stop_sltp_bracket_enabled: true,
            ..GatewayFeatureSet::default()
        };
        let flagged = features.real_order_endpoint_gate_decision();
        assert!(!flagged.endpoint_calls_allowed);
        assert_eq!(
            flagged.blocking_reasons,
            vec![
                RealOrderEndpointGateBlock::M3a11PreEndpointReviewRequired,
                RealOrderEndpointGateBlock::M3cImplementationReviewRequired,
                RealOrderEndpointGateBlock::RealOrderEndpointEnabled,
                RealOrderEndpointGateBlock::CommandConsumerEnabled,
                RealOrderEndpointGateBlock::OrderPlacementEnabled,
                RealOrderEndpointGateBlock::CancelEnabled,
                RealOrderEndpointGateBlock::StopSltpBracketEnabled,
            ]
        );
        assert!(EndpointGateApproved::try_from_decision(&flagged).is_err());
    }

    #[test]
    fn endpoint_gate_marker_cannot_be_forged_from_manual_decision() {
        let manual_decision = RealOrderEndpointGateDecision {
            endpoint_calls_allowed: true,
            blocking_reasons: vec![],
            runtime_ack_id_policy: RuntimeCommandAckIdPolicy::RedactedRuntimeAckOnly,
        };

        assert!(matches!(
            EndpointGateApproved::try_from_decision(&manual_decision)
                .expect_err("manual decision must not forge endpoint approval"),
            EndpointGateApprovalError::Blocked { decision } if !decision.endpoint_calls_allowed
                && decision
                    .blocking_reasons
                    .contains(&RealOrderEndpointGateBlock::M3a11PreEndpointReviewRequired)
                    && decision
                        .blocking_reasons
                        .contains(&RealOrderEndpointGateBlock::M3cImplementationReviewRequired)
        ));
    }

