    #[test]
    fn local_http_readonly_mapper_rejects_account_and_instrument_mismatch() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 1, 12, 19, 33)
            .single()
            .expect("timestamp");
        let policy = CancelBrokerTruthOrchestrationPolicy::default();
        let account_id = BrokerAccountId::new("ACC_TEST_0001");
        let order_id = BrokerOrderId::new("BROKER_TEST_SCOPE");
        let client_id = ClientOrderId::new("CID000000000000202").expect("client id");
        let instrument = sample_instrument();
        let request = truth_fetch_request_with_account(
            &account_id,
            &order_id,
            Some(&client_id),
            &instrument,
            now,
            CancelPositionTruthGuardContext::default(),
        );
        let request_snapshot = CancelBrokerTruthFetchRequestSnapshot::from(&request);
        let account_mismatch_body = serde_json::json!({
            "executed_quantity": {"value": "0"},
            "initial_quantity": {"value": "1"},
            "order": {
                "account_id": "ACC_TEST_OTHER",
                "client_order_id": client_id.as_str(),
                "limit_price": {"value": "5000"},
                "quantity": {"value": "1"},
                "side": "SIDE_BUY",
                "symbol": "TESTFUT@TEST",
                "type": "ORDER_TYPE_LIMIT"
            },
            "order_id": order_id.as_str(),
            "status": "ORDER_STATUS_CANCELED"
        });
        let result = map_cancel_broker_truth_get_order_http_response(
            &CancelBrokerTruthReadonlyHttpResponse::json(200, &account_mismatch_body),
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = result else {
            panic!("account mismatch should not become evidence");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::AccountMismatch);

        let instrument_mismatch_body = serde_json::json!({
            "executed_quantity": {"value": "0"},
            "initial_quantity": {"value": "1"},
            "order": {
                "account_id": account_id.as_str(),
                "client_order_id": client_id.as_str(),
                "limit_price": {"value": "5000"},
                "quantity": {"value": "1"},
                "side": "SIDE_BUY",
                "symbol": "OTHERFUT@TEST",
                "type": "ORDER_TYPE_LIMIT"
            },
            "order_id": order_id.as_str(),
            "status": "ORDER_STATUS_CANCELED"
        });
        let result = map_cancel_broker_truth_get_order_http_response(
            &CancelBrokerTruthReadonlyHttpResponse::json(200, &instrument_mismatch_body),
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = result else {
            panic!("instrument mismatch should not become evidence");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::InstrumentMismatch);

        let same_symbol_different_venue_body = serde_json::json!({
            "executed_quantity": {"value": "0"},
            "initial_quantity": {"value": "1"},
            "order": {
                "account_id": account_id.as_str(),
                "client_order_id": client_id.as_str(),
                "limit_price": {"value": "5000"},
                "quantity": {"value": "1"},
                "side": "SIDE_BUY",
                "symbol": "TESTFUT@OTHER",
                "type": "ORDER_TYPE_LIMIT"
            },
            "order_id": order_id.as_str(),
            "status": "ORDER_STATUS_CANCELED"
        });
        let result = map_cancel_broker_truth_get_order_http_response(
            &CancelBrokerTruthReadonlyHttpResponse::json(200, &same_symbol_different_venue_body),
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = result else {
            panic!("same symbol with different venue should not become evidence");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::InstrumentMismatch);
    }

    #[test]
    fn local_http_readonly_fetcher_maps_status_and_decode_failures_without_raw_body() {
        let now = Utc
            .with_ymd_and_hms(2026, 7, 1, 12, 19, 29)
            .single()
            .expect("timestamp");
        let policy = CancelBrokerTruthOrchestrationPolicy::default();
        let order_id = BrokerOrderId::new("BROKER_TEST_LOCAL_FAILURE");
        let client_id = ClientOrderId::new("CID000000000000199").expect("client id");
        let instrument = sample_instrument();
        let request = truth_fetch_request(
            &order_id,
            Some(&client_id),
            &instrument,
            now,
            CancelPositionTruthGuardContext::default(),
        );
        let request_snapshot = CancelBrokerTruthFetchRequestSnapshot::from(&request);

        let timeout = map_cancel_broker_truth_get_order_http_response(
            &CancelBrokerTruthReadonlyHttpResponse::empty(504),
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = timeout else {
            panic!("504 should map to missing timeout");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::Timeout);

        let maintenance = map_cancel_broker_truth_get_order_http_response(
            &CancelBrokerTruthReadonlyHttpResponse::empty(502),
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = maintenance else {
            panic!("502 should map to missing maintenance");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::Maintenance);

        let malformed = CancelBrokerTruthReadonlyHttpResponse::raw(
            200,
            format!(
                "{{\"order_id\":\"{}\",\"comment\":\"raw malformed body must not leak\"",
                order_id.as_str()
            ),
        );
        let decode_error = map_cancel_broker_truth_get_order_http_response(
            &malformed,
            &request_snapshot,
            now,
            &policy.freshness,
        );
        let CancelBrokerTruthFetchResult::Missing { reason, .. } = decode_error else {
            panic!("malformed 2xx body should map to decode error");
        };
        assert_eq!(reason, CancelBrokerTruthFetchReason::DecodeError);
        let rendered = format!("{malformed:?}");
        assert!(!rendered.contains(order_id.as_str()));
        assert!(!rendered.contains("raw malformed body must not leak"));
    }

    #[test]
    fn real_readonly_transport_error_category_is_redacted_and_maps_to_fetch_reason() {
        let response = CancelBrokerTruthReadonlyHttpResponse::empty_with_transport_error(
            504,
            FinamRealReadonlyTransportErrorCategory::Timeout,
        );
        let diagnostic = response.diagnostic();
        assert_eq!(
            diagnostic.transport_error_category,
            Some(FinamRealReadonlyTransportErrorCategory::Timeout)
        );
        assert_eq!(
            readonly_http_status_failure(diagnostic.status),
            Some(CancelBrokerTruthFetchReason::Timeout)
        );
        let rendered = format!("{response:?}");
        assert!(rendered.contains("Timeout"));
        assert!(!rendered.contains("https://"));
        assert!(!rendered.contains("ACCESS_TOKEN_TEST"));
    }

